#!/usr/bin/env bun

import { addSurfaceToState } from "./runtime/automation"
import { ensureEnvLocalSkeleton } from "./runtime/env-local"
import { getManagedDocSpecs, getManagedSkillSpecs, syncManagedFiles } from "./runtime/generated-files"
import { syncLocalBootstrapManifest } from "./runtime/local-bootstrap"
import { readState, writeState } from "./runtime/state-core"
import { validatePhaseGate } from "./runtime/validation/phase"

type ReporterState = {
  failCount: number
  passCount: number
  warnCount: number
}

function createInlineReporter(state: ReporterState) {
  return {
    pass(message: string) {
      console.log(`  ✅ ${message}`)
      state.passCount++
    },
    warn(message: string) {
      console.log(`  ⚠️  ${message}`)
      state.warnCount++
    },
    failSoft(message: string, hint?: string) {
      console.log(`  ❌ ${message}`)
      if (hint) console.log(`     → ${hint}`)
      state.failCount++
    },
    section(title: string) {
      console.log(`\n── ${title} ${"─".repeat(Math.max(0, 50 - title.length))}`)
    },
    finish(): never {
      throw new Error("inline reporter does not support finish()")
    },
  }
}

function getArg(flag: string): string | undefined {
  const args = process.argv.slice(2)
  const inline = args.find(arg => arg.startsWith(`${flag}=`))
  if (inline) return inline.slice(flag.length + 1)

  const index = args.indexOf(flag)
  if (index === -1) return undefined
  const next = args[index + 1]
  return next && !next.startsWith("--") ? next : undefined
}

const type = getArg("--type")
const workspace = getArg("--workspace")

if (!type) {
  console.error("Usage: bun .harness/add-surface.ts --type <web-app|ios-app|cli|agent|desktop> [--workspace <name>]")
  process.exit(1)
}

const state = readState()
const result = addSurfaceToState(state, type, workspace)
syncManagedFiles(getManagedDocSpecs(result.state))
syncManagedFiles(getManagedSkillSpecs(result.state))
const updated = writeState(result.state)
ensureEnvLocalSkeleton(updated)
syncLocalBootstrapManifest()

const validationPhase: "SCAFFOLD" | "EXECUTING" =
  ["EXECUTING", "VALIDATING", "COMPLETE"].includes(updated.phase) ? "EXECUTING" : "SCAFFOLD"

const reporterState: ReporterState = { failCount: 0, passCount: 0, warnCount: 0 }
await validatePhaseGate(validationPhase, updated, createInlineReporter(reporterState))

if (reporterState.failCount > 0) {
  console.error(`\n${reporterState.failCount} issue(s) need to be fixed after adding the new surface.`)
  process.exit(1)
}

console.log(
  `✅ surface ${result.changed ? "added" : "reconciled"}: ${result.surface} -> apps/${result.workspace}`,
)

#!/usr/bin/env bun
/**
 * .harness/advance.ts
 *
 * Runtime-owned phase advancement entrypoint.
 * Validates the next phase gate first, then advances state only if the gate passes.
 */

import type { Phase, ProjectState } from "./types"
import { deriveExecutionFromPrd } from "./runtime/backlog"
import { writeState } from "./runtime/state-core"
import { validatePhaseGate } from "./runtime/validation/phase"
import { loadState, saveState, syncStateFromFilesystem } from "./runtime/validation/state"

type ReporterState = {
  failCount: number
  warnCount: number
  passCount: number
}

function createAdvanceReporter(state: ReporterState) {
  return {
    pass(message: string) {
      console.log(`  ✅ ${message}`)
      state.passCount++
    },
    warn(message: string) {
      console.warn(`  ⚠️  ${message}`)
      state.warnCount++
    },
    failSoft(message: string, hint?: string) {
      console.error(`  ❌ ${message}`)
      if (hint) console.error(`     → ${hint}`)
      state.failCount++
    },
    section(title: string) {
      console.log(`\n── ${title} ${"─".repeat(Math.max(0, 50 - title.length))}`)
    },
    finish() {
      throw new Error("advance reporter does not support finish()")
    },
  }
}

function getNextPhase(current: Phase): Phase | null {
  switch (current) {
    case "DISCOVERY":
      return "MARKET_RESEARCH"
    case "MARKET_RESEARCH":
      return "TECH_STACK"
    case "TECH_STACK":
      return "PRD_ARCH"
    case "PRD_ARCH":
      return "SCAFFOLD"
    case "SCAFFOLD":
      return "EXECUTING"
    case "EXECUTING":
      return "VALIDATING"
    case "VALIDATING":
      return "COMPLETE"
    case "COMPLETE":
      return null
  }
}

async function validateGateOrExit(phase: Phase, state: ProjectState): Promise<void> {
  const reporterState: ReporterState = { passCount: 0, warnCount: 0, failCount: 0 }
  const reporter = createAdvanceReporter(reporterState)
  await validatePhaseGate(phase, state, reporter)

  if (reporterState.failCount > 0) {
    console.error(`\n${reporterState.failCount} issue(s) need to be fixed. See references/gates-and-guardians.md`)
    process.exit(1)
  }
}

const loaded = loadState(true)
const state = syncStateFromFilesystem(loaded!)
saveState(state)

const nextPhase = getNextPhase(state.phase)
if (!nextPhase) {
  console.log("ℹ️  Project is already at COMPLETE. No further phase advancement is available.")
  process.exit(0)
}

let nextState = state
if (state.phase === "SCAFFOLD") {
  nextState = deriveExecutionFromPrd(state)
} else {
  nextState = { ...state, phase: nextPhase }
}

await validateGateOrExit(nextPhase, nextState)

const persisted = writeState(nextState)
console.log(`\n✅ phase advanced: ${state.phase} -> ${persisted.phase}`)
if (persisted.phase === "EXECUTING") {
  console.log(`   Current Task: ${persisted.execution.currentTask || "—"}  |  Worktree: ${persisted.execution.currentWorktree || "—"}`)
}

#!/usr/bin/env bun

import { createApiWrapperService } from "./runtime/automation"
import { readState, writeState } from "./runtime/state-core"
import { getManagedSkillSpecs, syncManagedFiles } from "./runtime/generated-files"
import { syncLocalBootstrapManifest } from "./runtime/local-bootstrap"

function getArg(flag: string): string | undefined {
  const args = process.argv.slice(2)
  const inline = args.find(arg => arg.startsWith(`${flag}=`))
  if (inline) return inline.slice(flag.length + 1)

  const index = args.indexOf(flag)
  if (index === -1) return undefined
  const next = args[index + 1]
  return next && !next.startsWith("--") ? next : undefined
}

const name = getArg("--name")
const source = (getArg("--source") ?? "manual") as "manual" | "openapi"
const spec = getArg("--spec")

if (!name) {
  console.error("Usage: bun .harness/api-add.ts --name <service> [--source openapi|manual] [--spec <path>]")
  process.exit(1)
}

if (!["manual", "openapi"].includes(source)) {
  console.error('Unsupported --source value. Use "manual" or "openapi".')
  process.exit(1)
}

const state = readState()
const result = createApiWrapperService(state, name, source, spec)
syncManagedFiles(getManagedSkillSpecs(state))
writeState(state)
syncLocalBootstrapManifest()

console.log(`✅ api wrapper ${result.created ? "created" : "already present"}: ${result.path}`)

#!/usr/bin/env bun

import { existsSync, mkdirSync, readFileSync, writeFileSync } from "fs"
import { dirname } from "path"
import type { ValidationReporter } from "./runtime/validation/reporter"
import { validateEnv, validateGuardians } from "./runtime/validation/env-and-guardians"
import { validatePhaseGate } from "./runtime/validation/phase"
import { getManagedDocSpecs, getManagedSkillSpecs, hasManagedDrift } from "./runtime/generated-files"
import { runBun } from "./runtime/validation/helpers"
import { loadState, saveState, syncStateFromFilesystem } from "./runtime/validation/state"
import { hasAgentSurface, surfaceWorkspaceList } from "./runtime/surfaces"

type AuditEntry = {
  hint?: string
  message: string
  status: "pass" | "warn" | "fail" | "section"
}

function createAuditReporter(entries: AuditEntry[]): ValidationReporter {
  return {
    pass(message: string) {
      console.log(`  ✅ ${message}`)
      entries.push({ status: "pass", message })
    },
    warn(message: string) {
      console.log(`  ⚠️  ${message}`)
      entries.push({ status: "warn", message })
    },
    failSoft(message: string, hint?: string) {
      console.log(`  ❌ ${message}`)
      if (hint) console.log(`     → ${hint}`)
      entries.push({ status: "fail", message, hint })
    },
    section(title: string) {
      console.log(`\n── ${title} ${"─".repeat(Math.max(0, 50 - title.length))}`)
      entries.push({ status: "section", message: title })
    },
    finish(): never {
      throw new Error("finish() is not used in harness-audit.ts")
    },
  }
}

function auditWorkspaceContract(entries: AuditEntry[], state: ReturnType<typeof syncStateFromFilesystem>): void {
  const reporter = createAuditReporter(entries)
  reporter.section("Workspace Contract")

  const pkg = existsSync("package.json")
    ? (JSON.parse(readFileSync("package.json", "utf-8")) as { workspaces?: string[] })
    : { workspaces: [] }
  const workspaces = pkg.workspaces ?? []

  if (workspaces.includes("apps/*")) reporter.pass("package.json includes apps/* workspace")
  else reporter.failSoft("package.json is missing apps/* workspace")

  if (workspaces.includes("packages/*")) reporter.pass("package.json includes packages/* workspace")
  else reporter.failSoft("package.json is missing packages/* workspace")

  for (const workspace of surfaceWorkspaceList(state.projectInfo.types)) {
    if (existsSync(`apps/${workspace}/package.json`)) {
      reporter.pass(`apps/${workspace}/package.json is present`)
    } else {
      reporter.failSoft(`apps/${workspace}/package.json is present`)
    }
  }

  if (existsSync("packages/shared/package.json")) {
    reporter.pass("packages/shared/package.json is present")
  } else {
    reporter.failSoft("packages/shared/package.json is present")
  }
}

function auditManagedDrift(entries: AuditEntry[], state: ReturnType<typeof syncStateFromFilesystem>): void {
  const reporter = createAuditReporter(entries)

  reporter.section("Docs Drift")
  for (const spec of getManagedDocSpecs(state)) {
    if (hasManagedDrift(spec)) {
      reporter.failSoft(`${spec.path} is out of sync`, "Run bun harness:sync-docs")
    } else {
      reporter.pass(`${spec.path} is synchronized`)
    }
  }

  reporter.section("Skills Drift")
  const skillSpecs = getManagedSkillSpecs(state)
  if (skillSpecs.length === 0) {
    reporter.warn("No agent skill catalog is required for the current project types")
    return
  }

  for (const spec of skillSpecs) {
    if (hasManagedDrift(spec)) {
      reporter.failSoft(`${spec.path} is out of sync`, "Run bun harness:sync-skills")
    } else {
      reporter.pass(`${spec.path} is synchronized`)
    }
  }
}

async function auditCompact(entries: AuditEntry[]): Promise<void> {
  const reporter = createAuditReporter(entries)
  reporter.section("Compact Status")
  const result = await runBun(["run", "harness:compact:status"])
  if (result.ok) reporter.pass("harness:compact:status runs successfully")
  else reporter.failSoft("harness:compact:status failed", result.output)
}

function auditAgentBaseline(entries: AuditEntry[], state: ReturnType<typeof syncStateFromFilesystem>): void {
  if (!hasAgentSurface(state.projectInfo.types)) return

  const reporter = createAuditReporter(entries)
  reporter.section("Agent Skill Baseline")

  if (existsSync("SKILLS.md")) reporter.pass("SKILLS.md is present")
  else reporter.failSoft("SKILLS.md is present")

  if (existsSync("skills/api-wrapper/SKILL.md")) reporter.pass("skills/api-wrapper/SKILL.md is present")
  else reporter.failSoft("skills/api-wrapper/SKILL.md is present")

  if (existsSync("packages/shared/api/README.md")) reporter.pass("packages/shared/api/README.md is present")
  else reporter.failSoft("packages/shared/api/README.md is present")
}

function writeAuditReport(entries: AuditEntry[]): string {
  const reportPath = ".harness/reports/audit-latest.md"
  mkdirSync(dirname(reportPath), { recursive: true })

  const lines: string[] = ["# Harness Audit", ""]
  for (const entry of entries) {
    if (entry.status === "section") {
      lines.push(`## ${entry.message}`)
      lines.push("")
      continue
    }

    const icon =
      entry.status === "pass" ? "✅" : entry.status === "warn" ? "⚠️" : "❌"
    lines.push(`- ${icon} ${entry.message}`)
    if (entry.hint) lines.push(`  - Hint: ${entry.hint}`)
  }

  writeFileSync(reportPath, `${lines.join("\n")}\n`)
  return reportPath
}

const entries: AuditEntry[] = []
const reporter = createAuditReporter(entries)
const loaded = loadState(true)
const state = syncStateFromFilesystem(loaded!)
saveState(state)

await validateEnv(reporter)
await validateGuardians(reporter)
await validatePhaseGate(state.phase, state, reporter)
auditWorkspaceContract(entries, state)
auditManagedDrift(entries, state)
auditAgentBaseline(entries, state)
await auditCompact(entries)

const reportPath = writeAuditReport(entries)
const failCount = entries.filter(entry => entry.status === "fail").length
const warnCount = entries.filter(entry => entry.status === "warn").length

console.log(`\nAudit report written to ${reportPath}`)
if (failCount > 0) {
  console.error(`Audit failed with ${failCount} issue(s) and ${warnCount} warning(s).`)
  process.exit(1)
}

console.log(`✅ Audit passed (${warnCount} warning(s))`)

#!/usr/bin/env bun
/**
 * harness-compact.ts
 *
 * Context health management for AI agents.
 * Generates CONTEXT_SNAPSHOT.md with retention-tiered information
 * so agents can safely compact conversation context.
 *
 * Usage:
 *   bun .harness/compact.ts              → Task-level snapshot
 *   bun .harness/compact.ts --milestone  → Milestone-level archive + suggest /clear
 *   bun .harness/compact.ts --milestone --milestone-id M[N] → Archive a specific milestone during closeout
 *   bun .harness/compact.ts --status     → Show context health advice
 */

import { existsSync, mkdirSync, readdirSync, readFileSync, writeFileSync } from "fs"
import { join } from "path"

const STATE_PATH = ".harness/state.json"
const SNAPSHOT_PATH = "docs/progress/CONTEXT_SNAPSHOT.md"
const ADR_DIR = "docs/adr"
const PROGRESS_DIR = "docs/progress"

interface MinimalState {
  phase: string
  execution: {
    currentMilestone: string
    currentTask: string
    currentWorktree: string
    milestones: MinimalMilestone[]
  }
}

interface MinimalMilestone {
  id: string
  name: string
  status: string
  tasks: Array<{
    id: string
    name: string
    status: string
    commitHash?: string
  }>
}

function readState(): MinimalState | null {
  if (!existsSync(STATE_PATH)) return null
  try {
    return JSON.parse(readFileSync(STATE_PATH, "utf-8")) as MinimalState
  } catch {
    return null
  }
}

function collectAdrSummaries(): string[] {
  if (!existsSync(ADR_DIR)) return []
  return readdirSync(ADR_DIR)
    .filter(f => /^ADR-\d{3}.*\.md$/i.test(f))
    .sort()
    .slice(-5)
    .map(file => {
      const content = readFileSync(join(ADR_DIR, file), "utf-8")
      const heading = content.match(/^#\s+(.+)/m)?.[1] ?? file
      return `- ${file}: ${heading}`
    })
}

function collectRecentLearning(): string[] {
  const home = Bun.env.HOME ?? Bun.env.USERPROFILE ?? ""
  const sep = process.platform === "win32" ? "\\" : "/"
  const paths = [
    `${home}${sep}.codex${sep}LEARNING.md`,
    `${home}${sep}.claude${sep}LEARNING.md`,
  ]

  for (const p of paths) {
    if (!existsSync(p)) continue
    const content = readFileSync(p, "utf-8")
    const entries = content.split(/^##\s+/m).filter(Boolean).slice(-5)
    if (entries.length > 0) {
      return entries.map(e => `- ${e.split("\n")[0]?.trim() ?? "(untitled)"}`)
    }
  }
  return []
}

function getCompletedTasks(state: MinimalState): Array<{ id: string; name: string; commitHash?: string }> {
  return state.execution.milestones
    .flatMap(m => m.tasks)
    .filter(t => t.status === "DONE")
    .slice(-3)
}

function resolveMilestoneTarget(state: MinimalState, milestoneId?: string): MinimalMilestone | undefined {
  if (milestoneId) {
    return state.execution.milestones.find(milestone => milestone.id === milestoneId)
  }

  return state.execution.milestones.find(m => m.id === state.execution.currentMilestone)
}

function getRemainingTasks(
  state: MinimalState,
  milestoneId?: string,
): Array<{ id: string; name: string; status: string }> {
  const milestone = resolveMilestoneTarget(state, milestoneId)
  if (!milestone) return []
  return milestone.tasks.filter(t => t.status !== "DONE" && t.status !== "SKIPPED")
}

function getMilestoneArchiveTasks(
  milestone?: MinimalMilestone,
): Array<{ commitHash?: string; id: string; name: string; status: string }> {
  return milestone?.tasks ?? []
}

function generateSnapshot(state: MinimalState, isMilestone: boolean, milestoneId?: string): string {
  const now = new Date().toISOString()
  const recentTasks = getCompletedTasks(state)
  const targetMilestone = resolveMilestoneTarget(state, milestoneId)
  const remaining = getRemainingTasks(state, milestoneId)
  const archiveTasks = getMilestoneArchiveTasks(targetMilestone)
  const adrSummaries = collectAdrSummaries()
  const learningEntries = collectRecentLearning()

  const lines: string[] = []
  lines.push(`# CONTEXT_SNAPSHOT`)
  lines.push(``)
  lines.push(`> Generated: ${now}`)
  lines.push(`> Mode: ${isMilestone ? "milestone" : "task"}`)
  lines.push(``)

  // 🔴 RETAIN
  lines.push(`## 🔴 RETAIN — Must Keep`)
  lines.push(``)
  lines.push(`- **Phase**: ${state.phase}`)
  lines.push(`- **Milestone**: ${targetMilestone?.id ?? state.execution.currentMilestone}`)
  lines.push(`- **Task**: ${state.execution.currentTask}`)
  lines.push(`- **Worktree**: ${state.execution.currentWorktree || "main"}`)
  lines.push(``)
  if (adrSummaries.length > 0) {
    lines.push(`### Recent ADR Decisions`)
    lines.push(``)
    for (const adr of adrSummaries) {
      lines.push(adr)
    }
    lines.push(``)
  }

  // 🟡 PREFER
  lines.push(`## 🟡 PREFER — Keep if Possible`)
  lines.push(``)
  if (recentTasks.length > 0) {
    lines.push(`### Last ${recentTasks.length} Completed Tasks`)
    lines.push(``)
    for (const t of recentTasks) {
      lines.push(`- ${t.id}: ${t.name}${t.commitHash ? ` (${t.commitHash.slice(0, 7)})` : ""}`)
    }
    lines.push(``)
  }
  if (!isMilestone && remaining.length > 0) {
    lines.push(`### Remaining Tasks (current milestone)`)
    lines.push(``)
    for (const t of remaining) {
      lines.push(`- ${t.id}: ${t.name} [${t.status}]`)
    }
    lines.push(``)
  }
  if (learningEntries.length > 0) {
    lines.push(`### Recent LEARNING.md Entries`)
    lines.push(``)
    for (const entry of learningEntries) {
      lines.push(entry)
    }
    lines.push(``)
  }

  // 🟢 SAFE TO DISCARD
  lines.push(`## 🟢 SAFE TO DISCARD`)
  lines.push(``)
  lines.push(`- Old typecheck/lint/test/build full output from completed Tasks`)
  lines.push(`- Debug loop intermediate attempts`)
  lines.push(`- Design Review detailed line-by-line comparisons`)
  lines.push(`- Full file contents that were read but not modified`)
  lines.push(`- Git diff/log output from completed Tasks`)
  lines.push(``)

  if (isMilestone) {
    lines.push(`## 📦 Milestone Archive`)
    lines.push(``)
    if (targetMilestone) {
      lines.push(`- Target milestone: ${targetMilestone.id} — ${targetMilestone.name} [${targetMilestone.status}]`)
      lines.push(``)
      lines.push(`### Milestone Tasks`)
      lines.push(``)
      for (const task of archiveTasks) {
        lines.push(
          `- ${task.id}: ${task.name} [${task.status}]${task.commitHash ? ` (${task.commitHash.slice(0, 7)})` : ""}`,
        )
      }
      lines.push(``)
    }
    lines.push(`All Tasks in the target milestone have been completed and are ready for merge closeout.`)
    lines.push(`Consider running \`/compact\` with the above snapshot as retention guidance.`)
    lines.push(``)
  }

  return lines.join("\n")
}

function showStatus(state: MinimalState | null): void {
  console.log(`\n${"═".repeat(50)}`)
  console.log("  Context Health Status")
  console.log(`${"═".repeat(50)}\n`)

  if (!state) {
    console.log("⚠️  No state.json found. Run: bun .harness/init.ts")
    return
  }

  console.log(`Phase:     ${state.phase}`)
  console.log(`Milestone: ${state.execution.currentMilestone}`)
  console.log(`Task:      ${state.execution.currentTask}`)
  console.log(`Worktree:  ${state.execution.currentWorktree || "main"}`)
  console.log("")

  const snapshotExists = existsSync(SNAPSHOT_PATH)
  if (snapshotExists) {
    const content = readFileSync(SNAPSHOT_PATH, "utf-8")
    const match = content.match(/Generated:\s*(.+)/)
    console.log(`Last snapshot: ${match?.[1] ?? "unknown"}`)
  } else {
    console.log("Last snapshot: none")
  }

  console.log("")
  console.log("Recommendations:")
  console.log("  • Run `bun harness:compact` after each Task completion")
  console.log("  • Milestone closeout auto-runs `bun .harness/compact.ts --milestone --milestone-id M[N]`")
  console.log("  • Use snapshot as /compact retention guidance")
  console.log("")
}

// ─── Main ────────────────────────────────────────────────────────────────────

const args = process.argv.slice(2)
const isMilestone = args.includes("--milestone")
const isStatus = args.includes("--status")
const milestoneId =
  args.find(arg => arg.startsWith("--milestone-id="))?.slice("--milestone-id=".length) ??
  (() => {
    const index = args.indexOf("--milestone-id")
    const next = index === -1 ? undefined : args[index + 1]
    return next && !next.startsWith("--") ? next : undefined
  })()

const state = readState()

if (isStatus) {
  showStatus(state)
  process.exit(0)
}

if (!state) {
  console.error("❌ .harness/state.json not found. Run: bun .harness/init.ts")
  process.exit(1)
}

if (isMilestone && milestoneId && !resolveMilestoneTarget(state, milestoneId)) {
  console.error(`❌ Milestone ${milestoneId} was not found in .harness/state.json`)
  process.exit(1)
}

const snapshot = generateSnapshot(state, isMilestone, milestoneId)

mkdirSync(PROGRESS_DIR, { recursive: true })
writeFileSync(SNAPSHOT_PATH, snapshot)

console.log(`\n✅ CONTEXT_SNAPSHOT.md ${isMilestone ? "(milestone)" : "(task)"} written to ${SNAPSHOT_PATH}`)
if (isMilestone) {
  console.log("\n💡 Milestone complete. Consider running /compact to clear conversation context.")
}
console.log("")

#!/usr/bin/env bun
/**
 * harness-init.ts
 *
 * State management utility for Phase 4/5.
 * Responsibilities:
 * - initialize .harness/state.json
 * - parse milestone / task backlog from docs/PRD.md or docs/prd/
 * - synchronize docs/PROGRESS.md and docs/progress/ after state changes
 */

import { existsSync } from "fs"
import { bootstrapExecutionFromPrd, syncExecutionBacklogFromPrd } from "./runtime/backlog"
import { advancePhase, blockTask, completeMilestone, completeTask } from "./runtime/execution"
import { getLearningPaths, syncLearning } from "./runtime/learning"
import { ensureProjectDirs, initState, readState, updateState, writeState } from "./runtime/state-core"
import { STATE_PATH } from "./runtime/shared"

export {
  advancePhase,
  blockTask,
  bootstrapExecutionFromPrd,
  completeMilestone,
  completeTask,
  getLearningPaths,
  initState,
  syncExecutionBacklogFromPrd,
  syncLearning,
  updateState,
}

function getArgValue(flag: string): string | undefined {
  const args = process.argv.slice(2)
  const inline = args.find(arg => arg.startsWith(`${flag}=`))
  if (inline) return inline.slice(flag.length + 1)

  const index = args.indexOf(flag)
  if (index === -1) return undefined
  const next = args[index + 1]
  return next && !next.startsWith("--") ? next : undefined
}

if (import.meta.main) {
  ensureProjectDirs()

  if (process.argv.includes("--from-prd")) {
    const updated = bootstrapExecutionFromPrd()
    console.log(`✅ Created ${updated.execution.milestones.length} milestone(s) from docs/prd/ (or docs/PRD.md)`)
    console.log(
      `   Current task: ${updated.execution.currentTask || "—"}  |  Worktree: ${updated.execution.currentWorktree || "—"}`,
    )
  } else if (process.argv.includes("--sync-from-prd")) {
    const updated = syncExecutionBacklogFromPrd()
    console.log(
      `✅ Synced PRD backlog: +${updated.addedMilestones} milestone(s), +${updated.addedTasks} task(s)`,
    )
    console.log(
      `   Current task: ${updated.state.execution.currentTask || "—"}  |  Worktree: ${updated.state.execution.currentWorktree || "—"}`,
    )
  } else if (process.argv.includes("--complete-task")) {
    const taskId = getArgValue("--complete-task")
    const commitHash = getArgValue("--commit")

    if (!taskId || !commitHash) {
      console.error("Usage: bun .harness/init.ts --complete-task T001 --commit <hash>")
      process.exit(1)
    }

    completeTask(taskId, commitHash)
  } else if (!existsSync(STATE_PATH)) {
    const state = writeState(initState({}))
    console.log("✅ .harness/state.json initialized")
    console.log(`   Phase: ${state.phase}`)
    console.log("   Next step: fill in projectInfo, then run bun harness:advance")
  } else {
    const state = writeState(readState())
    console.log("ℹ️  .harness/state.json already exists; derived state and PROGRESS.md were synchronized")
    console.log(`   Phase: ${state.phase}`)
  }
}

#!/usr/bin/env bun
/**
 * .harness/merge-milestone.ts
 *
 * Compacts a REVIEW milestone, merges its branch into main, removes the
 * worktree, deletes the branch, and updates state to MERGED.
 */

import { completeMilestone } from "./runtime/execution"
import { readState } from "./runtime/state-core"

function run(cmd: string[]): { ok: boolean; stdout: string; stderr: string } {
  const proc = Bun.spawnSync(cmd, { stdout: "pipe", stderr: "pipe" })
  return {
    ok: proc.exitCode === 0,
    stdout: new TextDecoder().decode(proc.stdout).trim(),
    stderr: new TextDecoder().decode(proc.stderr).trim(),
  }
}

const milestoneId = process.argv[2]
if (!milestoneId) {
  console.error("Usage: bun .harness/merge-milestone.ts M[N]")
  process.exit(1)
}

const state = readState()
const milestone = state.execution.milestones.find(m => m.id === milestoneId)
if (!milestone) {
  console.error(`❌ Milestone ${milestoneId} not found in state`)
  process.exit(1)
}
if (milestone.status !== "REVIEW") {
  console.error(`❌ Milestone ${milestoneId} is ${milestone.status}, expected REVIEW`)
  process.exit(1)
}

// Ensure we are on main or master
const branchResult = run(["git", "rev-parse", "--abbrev-ref", "HEAD"])
if (!branchResult.ok) {
  console.error("❌ Could not determine current branch")
  process.exit(1)
}
const currentBranch = branchResult.stdout
if (currentBranch !== "main" && currentBranch !== "master") {
  console.error(`❌ Must be on main or master to merge. Currently on: ${currentBranch}`)
  process.exit(1)
}

// Build merge commit message
const taskRange = milestone.tasks.length > 0
  ? `${milestone.tasks[0].id}-${milestone.tasks[milestone.tasks.length - 1].id}`
  : "no-tasks"
const mergeMessage = `feat(${milestone.id.toLowerCase()}): ${milestone.name} [${taskRange}]`

console.log(`\n🧠 Writing milestone snapshot for ${milestone.id}...`)
const compactResult = run(["bun", ".harness/compact.ts", "--milestone", "--milestone-id", milestone.id])
if (!compactResult.ok) {
  console.error(`❌ Milestone compact failed: ${compactResult.stderr || compactResult.stdout}`)
  process.exit(1)
}

console.log(`\n🔀 Merging ${milestone.branch} into ${currentBranch}...`)
const mergeResult = run(["git", "merge", "--no-ff", milestone.branch, "-m", mergeMessage])
if (!mergeResult.ok) {
  console.error(`❌ Merge failed: ${mergeResult.stderr}`)
  console.error("   Resolve conflicts, then re-run this command.")
  process.exit(1)
}

// Get the merge commit hash
const hashResult = run(["git", "rev-parse", "HEAD"])
const mergeCommit = hashResult.ok ? hashResult.stdout : "unknown"

// Remove worktree (warn on failure)
if (milestone.worktreePath) {
  console.log(`🗂  Removing worktree: ${milestone.worktreePath}`)
  const wtResult = run(["git", "worktree", "remove", milestone.worktreePath])
  if (!wtResult.ok) {
    console.warn(`⚠️  Could not remove worktree: ${wtResult.stderr}`)
    console.warn("   You may need to remove it manually: git worktree remove " + milestone.worktreePath)
  }
}

// Delete branch (warn on failure)
console.log(`🌿 Deleting branch: ${milestone.branch}`)
const branchDeleteResult = run(["git", "branch", "-d", milestone.branch])
if (!branchDeleteResult.ok) {
  console.warn(`⚠️  Could not delete branch: ${branchDeleteResult.stderr}`)
  console.warn("   You may need to delete it manually: git branch -D " + milestone.branch)
}

// Update state
completeMilestone(milestoneId, mergeCommit)
console.log(`\n✅ Milestone ${milestoneId} merged and state updated.`)

#!/usr/bin/env bun
/**
 * .harness/orchestrator.ts
 *
 * Stateless CLI — reads state.json + filesystem, decides which Agent to execute next,
 * outputs formatted context for Claude Code or Codex to consume.
 *
 * No API calls, no state modification.
 */

import { existsSync } from "fs"
import { runAutoflow } from "./runtime/orchestrator/autoflow"
import { dispatch, dispatchCodeReview, dispatchDesignReview, getStatus } from "./runtime/orchestrator/dispatcher"
import { deriveStateFromFilesystem, STATE_PATH } from "./runtime/shared"
import { readProjectStateFromDisk } from "./runtime/state-io"

if (!existsSync(STATE_PATH)) {
  console.error("❌ .harness/state.json does not exist. Run bun .harness/init.ts to initialize.")
  process.exit(1)
}

const state = deriveStateFromFilesystem(readProjectStateFromDisk(STATE_PATH), {
  updateProgressTimestamp: false,
  updateValidationTimestamp: false,
})

const args = process.argv.slice(2)

if (args.includes("--auto")) {
  process.exit(await runAutoflow())
}

if (args.includes("--status")) {
  console.log(getStatus(state))
  process.exit(0)
}

if (args.includes("--review")) {
  const reviewResult = dispatchDesignReview(state)
  if (args.includes("--packet-json")) {
    const payload =
      reviewResult.type === "agent" && reviewResult.packet
        ? reviewResult.packet
        : { message: reviewResult.message, type: reviewResult.type }
    console.log(JSON.stringify(payload, null, 2))
    process.exit(reviewResult.type === "agent" ? 0 : 1)
  }
  if (args.includes("--next")) {
    console.log(reviewResult.type === "agent" && reviewResult.agentId ? reviewResult.agentId : reviewResult.message)
    process.exit(reviewResult.type === "agent" ? 0 : 1)
  }
  if (reviewResult.type === "agent" && reviewResult.context) {
    console.log(reviewResult.context)
  } else {
    console.error(reviewResult.message)
    process.exit(1)
  }
  process.exit(0)
}

if (args.includes("--code-review")) {
  const codeReviewResult = dispatchCodeReview(state)
  if (args.includes("--packet-json")) {
    const payload =
      codeReviewResult.type === "agent" && codeReviewResult.packet
        ? codeReviewResult.packet
        : { message: codeReviewResult.message, type: codeReviewResult.type }
    console.log(JSON.stringify(payload, null, 2))
    process.exit(codeReviewResult.type === "agent" ? 0 : 1)
  }
  if (args.includes("--next")) {
    console.log(codeReviewResult.type === "agent" && codeReviewResult.agentId ? codeReviewResult.agentId : codeReviewResult.message)
    process.exit(codeReviewResult.type === "agent" ? 0 : 1)
  }
  if (codeReviewResult.type === "agent" && codeReviewResult.context) {
    console.log(codeReviewResult.context)
  } else {
    console.error(codeReviewResult.message)
    process.exit(1)
  }
  process.exit(0)
}

const result = dispatch(state)

if (args.includes("--packet-json")) {
  const payload =
    result.type === "agent" && result.packet
      ? result.packet
      : { message: result.message, type: result.type }
  console.log(JSON.stringify(payload, null, 2))
  process.exit(result.type === "agent" ? 0 : 1)
}

if (args.includes("--next")) {
  if (result.type === "agent" && result.agentId) {
    console.log(result.agentId)
  } else {
    console.log(result.message)
  }
  process.exit(result.type === "agent" ? 0 : 1)
}

if (result.type === "agent" && result.context) {
  console.log(result.context)
  if (result.postAction) {
    console.log(`\n${"─".repeat(40)} Post-Action`)
    console.log(result.postAction)
  }
} else {
  console.log(result.message)
  process.exit(1)
}

#!/usr/bin/env bun
/**
 * .harness/resume.ts
 *
 * Quickly resume an in-progress Harness project.
 * Reads .harness/state.json + docs/PROGRESS.md and prints
 * a clear summary of current state and next steps.
 *
 * Usage:
 *   bun .harness/resume.ts
 *
 * Typical use cases:
 * - resuming work the next day
 * - switching machines
 * - loading context at the start of a new Codex / Claude Code session
 */

import { existsSync, readdirSync, readFileSync } from "fs"
import { join } from "path"
import type { ProjectState } from "./types"

function loadState(): ProjectState | null {
  if (!existsSync(".harness/state.json")) return null
  return JSON.parse(readFileSync(".harness/state.json", "utf-8"))
}

function loadProgress(): string {
  const snapshotPath = "docs/progress/CONTEXT_SNAPSHOT.md"
  const parts: string[] = []

  if (existsSync("docs/PROGRESS.md")) {
    parts.push(readFileSync("docs/PROGRESS.md", "utf-8").trim())
  }

  if (existsSync(snapshotPath)) {
    parts.push(readFileSync(snapshotPath, "utf-8").trim())
  }

  if (parts.length > 0) {
    return parts.filter(Boolean).join("\n\n")
  }

  const modularDir = "docs/progress"
  if (existsSync(modularDir)) {
    const modules = readdirSync(modularDir)
      .filter(file => file.toLowerCase().endsWith(".md"))
      .sort()
      .map(file => readFileSync(join(modularDir, file), "utf-8").trim())
      .filter(Boolean)

    if (modules.length > 0) {
      return modules.join("\n\n")
    }
  }

  return ""
}

function phaseLabel(phase: string): string {
  const labels: Record<string, string> = {
    DISCOVERY: "Phase 0: Project Discovery",
    MARKET_RESEARCH: "Phase 1: Market Research",
    TECH_STACK: "Phase 2: Tech Stack Negotiation",
    PRD_ARCH: "Phase 3: PRD + Architecture",
    SCAFFOLD: "Phase 4: Scaffold Generation",
    EXECUTING: "Phase 5: Execution Engine",
    VALIDATING: "Phase 6: Harness Validation",
    COMPLETE: "✅ Project Complete",
  }
  return labels[phase] ?? phase
}

const state = loadState()
const progress = loadProgress()

if (!state) {
  console.error("❌ .harness/state.json is missing.")
  console.error("   Make sure you are in the correct project directory, or initialize the project first.")
  process.exit(1)
}

console.log(`\n${"═".repeat(60)}`)
console.log(`  📍 Harness Resume — ${state.projectInfo.displayName || state.projectInfo.name}`)
console.log(`${"═".repeat(60)}`)

console.log(`\n  Current phase: ${phaseLabel(state.phase)}`)
console.log(`  Last updated: ${new Date(state.updatedAt).toLocaleString()}`)
if (progress) {
  console.log("  Progress docs: docs/PROGRESS.md + docs/progress/CONTEXT_SNAPSHOT.md")
}

if (state.techStack.confirmed) {
  console.log("\n  Tech Stack:")
  for (const d of state.techStack.decisions.slice(0, 5)) {
    console.log(`    • ${d.layer}: ${d.choice}`)
  }
}

if (state.phase === "EXECUTING") {
  const { execution } = state
  const totalTasks = execution.milestones.flatMap(m => m.tasks).length
  const doneTasks = execution.milestones.flatMap(m => m.tasks).filter(t => t.status === "DONE").length
  const blockedTasks = execution.milestones.flatMap(m => m.tasks).filter(t => t.status === "BLOCKED")
  const pct = totalTasks ? Math.round((doneTasks / totalTasks) * 100) : 0
  const bar = "█".repeat(Math.round(pct / 5)) + "░".repeat(20 - Math.round(pct / 5))

  console.log(`\n  Execution progress: [${bar}] ${pct}% (${doneTasks}/${totalTasks} Tasks)`)
  console.log(`  Current milestone: ${execution.currentMilestone || "—"}`)
  console.log(`  Current task: ${execution.currentTask || "—"}`)
  if (execution.currentWorktree) {
    console.log(`  Current worktree: ${execution.currentWorktree}`)
  }

  if (blockedTasks.length > 0) {
    console.log("\n  ⚠️  BLOCKED tasks:")
    for (const t of blockedTasks) {
      console.log(`    • ${t.id}: ${t.name}`)
      console.log(`      Reason: ${t.blockedReason ?? "Not recorded"}`)
    }
  }
}

if (state.execution.milestones.length > 0) {
  console.log("\n  Milestones:")
  for (const m of state.execution.milestones) {
    const done = m.tasks.filter(t => t.status === "DONE").length
    const total = m.tasks.length
    const icon =
      m.status === "COMPLETE" || m.status === "MERGED"
        ? "✅"
        : m.status === "IN_PROGRESS"
          ? "⚙️ "
          : m.status === "REVIEW"
            ? "🟡"
            : "⏳"
    console.log(`    ${icon} ${m.id}: ${m.name} (${done}/${total})`)
  }
}

console.log(`\n${"─".repeat(60)}`)
console.log("  Next step:")

if (state.phase === "EXECUTING" && state.execution.currentTask) {
  console.log("")
  console.log("  With Codex:")
  console.log(
    `    codex "Read AGENTS.md, docs/PROGRESS.md, docs/progress/CONTEXT_SNAPSHOT.md if present, and .harness/state.json, then continue ${state.execution.currentTask}"`,
  )
  console.log("")
  console.log("  With Claude Code:")
  console.log(
    `    claude "Read CLAUDE.md, docs/PROGRESS.md, docs/progress/CONTEXT_SNAPSHOT.md if present, and .harness/state.json, then continue ${state.execution.currentTask}"`,
  )
} else if (state.phase === "COMPLETE") {
  console.log("    bun .harness/orchestrator.ts        → get the final closeout agent")
  console.log("    bun harness:compact --status        → inspect final context health")
} else {
  console.log("    bun .harness/orchestrator.ts        → get the current runtime dispatch")
  console.log("    bun .harness/orchestrator.ts --next → print only the next agent / action")
}

console.log("\n  Validation commands:")
if (state.phase === "EXECUTING") {
  const curMilestone = state.execution.currentMilestone
  if (curMilestone) {
    console.log(`    bun harness:validate --milestone ${curMilestone}`)
  }
  if (state.execution.currentTask) {
    console.log(`    bun harness:validate --task ${state.execution.currentTask}`)
  }
}
console.log("    bun harness:guardian  → run the guardian scan")
console.log("    bun harness:validate  → run full validation")
console.log(`${"═".repeat(60)}\n`)

import type { Milestone, ProjectState, Task } from "../types"

type GitResult = {
  ok: boolean
  output: string
}

export type AtomicCommitInspection = {
  baseLabel?: string
  branch: string
  commitCount?: number
  commitHash: string
  commitMessage: string
  ok: boolean
  reasons: string[]
}

function runGit(args: string[]): GitResult {
  try {
    const proc = Bun.spawnSync(["git", ...args], { stdout: "pipe", stderr: "pipe" })
    const stdout = new TextDecoder().decode(proc.stdout).trim()
    const stderr = new TextDecoder().decode(proc.stderr).trim()
    return { ok: proc.exitCode === 0, output: proc.exitCode === 0 ? stdout : stderr }
  } catch (error) {
    return { ok: false, output: String(error) }
  }
}

function getTaskLocation(
  state: ProjectState,
  taskId: string,
): { milestone: Milestone; milestoneIndex: number; task: Task; taskIndex: number } | null {
  for (const [milestoneIndex, milestone] of state.execution.milestones.entries()) {
    const taskIndex = milestone.tasks.findIndex(candidate => candidate.id === taskId)
    if (taskIndex !== -1) {
      return { milestone, milestoneIndex, task: milestone.tasks[taskIndex]!, taskIndex }
    }
  }

  return null
}

function getPreviousCommittedTask(milestone: Milestone, taskIndex: number): Task | undefined {
  return milestone.tasks
    .slice(0, taskIndex)
    .reverse()
    .find(task => task.status === "DONE" && Boolean(task.commitHash))
}

function resolveProtectedBaseBranch(): string | undefined {
  for (const branch of ["main", "master"]) {
    if (runGit(["show-ref", "--verify", "--quiet", `refs/heads/${branch}`]).ok) {
      return branch
    }
  }

  return undefined
}

export function inspectAtomicTaskCommit(
  state: ProjectState,
  taskId: string,
  commitHash: string,
): AtomicCommitInspection {
  const inspection: AtomicCommitInspection = {
    branch: "",
    commitHash: commitHash.trim(),
    commitMessage: "",
    ok: false,
    reasons: [],
  }

  const location = getTaskLocation(state, taskId)
  if (!location) {
    inspection.reasons.push(`Task ${taskId} was not found in state.`)
    return inspection
  }

  if (!inspection.commitHash) {
    inspection.reasons.push("Commit hash is required.")
    return inspection
  }

  const resolvedCommit = runGit(["rev-parse", "--verify", `${inspection.commitHash}^{commit}`])
  if (!resolvedCommit.ok) {
    inspection.reasons.push(`Commit ${inspection.commitHash} does not exist.`)
    return inspection
  }
  inspection.commitHash = resolvedCommit.output

  const branch = runGit(["branch", "--show-current"])
  if (!branch.ok || !branch.output) {
    inspection.reasons.push("Current git branch could not be determined.")
  } else {
    inspection.branch = branch.output
    if (inspection.branch === "main" || inspection.branch === "master") {
      inspection.reasons.push("Feature task commits must not be created on main/master.")
    }
  }

  const workingTree = runGit(["status", "--porcelain"])
  if (!workingTree.ok) {
    inspection.reasons.push("Working tree status could not be determined.")
  } else if (workingTree.output.trim().length > 0) {
    inspection.reasons.push("Working tree must be clean before marking a task DONE.")
  }

  const head = runGit(["rev-parse", "HEAD"])
  if (!head.ok) {
    inspection.reasons.push("HEAD commit could not be determined.")
  } else if (head.output !== inspection.commitHash) {
    inspection.reasons.push("The task commit must be the current HEAD commit.")
  }

  const commitMessage = runGit(["log", "-1", "--pretty=%B", inspection.commitHash])
  if (!commitMessage.ok) {
    inspection.reasons.push(`Commit message for ${inspection.commitHash} could not be read.`)
  } else {
    inspection.commitMessage = commitMessage.output
    if (!inspection.commitMessage.includes(location.task.id)) {
      inspection.reasons.push(`Commit message must include the current Task-ID (${location.task.id}).`)
    }
    if (!inspection.commitMessage.includes(location.task.prdRef)) {
      inspection.reasons.push(`Commit message must include the current PRD mapping (${location.task.prdRef}).`)
    }
  }

  const previousTask = getPreviousCommittedTask(location.milestone, location.taskIndex)
  if (previousTask?.commitHash) {
    inspection.baseLabel = previousTask.id
    const rangeCount = runGit(["rev-list", "--count", `${previousTask.commitHash}..${inspection.commitHash}`])
    if (!rangeCount.ok) {
      inspection.reasons.push(`Commit range from ${previousTask.id} could not be evaluated.`)
    } else {
      inspection.commitCount = Number.parseInt(rangeCount.output, 10)
      if (inspection.commitCount !== 1) {
        inspection.reasons.push(
          `Task ${location.task.id} must add exactly 1 commit after ${previousTask.id}; found ${inspection.commitCount}.`,
        )
      }
    }
  } else {
    const baseBranch = resolveProtectedBaseBranch()
    if (!baseBranch) {
      inspection.reasons.push("No main/master branch was found to compute atomic task range.")
    } else {
      inspection.baseLabel = baseBranch
      const mergeBase = runGit(["merge-base", inspection.commitHash, baseBranch])
      if (!mergeBase.ok || !mergeBase.output) {
        inspection.reasons.push(`Merge base against ${baseBranch} could not be determined.`)
      } else {
        const rangeCount = runGit(["rev-list", "--count", `${mergeBase.output}..${inspection.commitHash}`])
        if (!rangeCount.ok) {
          inspection.reasons.push(`Commit range from ${baseBranch} could not be evaluated.`)
        } else {
          inspection.commitCount = Number.parseInt(rangeCount.output, 10)
          if (inspection.commitCount !== 1) {
            inspection.reasons.push(
              `First task commit in milestone ${location.milestone.id} must be exactly 1 commit ahead of ${baseBranch}; found ${inspection.commitCount}.`,
            )
          }
        }
      }
    }
  }

  inspection.ok = inspection.reasons.length === 0
  return inspection
}

export function formatAtomicCommitFailure(taskId: string, inspection: AtomicCommitInspection): string {
  const lines = [`Task ${taskId} must be completed with one atomic commit:`]
  for (const reason of inspection.reasons) {
    lines.push(`- ${reason}`)
  }
  return lines.join("\n")
}

import { existsSync, mkdirSync, readFileSync, readdirSync, writeFileSync } from "fs"
import { join } from "path"
import type { Milestone, ProjectState, Task } from "../types"
import { createEmptyTaskChecklist } from "./task-checklist"
import { writeManagedFile } from "./generated-files"
import { isUiProject } from "./shared"
import {
  type AddableSurface,
  hasAgentSurface,
  isAddableSurface,
  normalizeProjectTypes,
  slugify,
  surfaceLabel,
  workspaceForSurface,
} from "./surfaces"

function readIfExists(path: string): string {
  return existsSync(path) ? readFileSync(path, "utf-8") : ""
}

function highestMatch(content: string, pattern: RegExp): number {
  return Math.max(
    0,
    ...Array.from(content.matchAll(pattern)).map(match => Number(match[1] ?? 0)),
  )
}

function nextMilestoneNumber(): number {
  const content = readIfExists("docs/prd/03-requirements.md")
  return highestMatch(content, /^###\s+Milestone\s+(\d+)/gm) + 1
}

function nextFeatureNumber(): number {
  const content = readIfExists("docs/prd/03-requirements.md")
  return highestMatch(content, /^####\s+F(\d{3})/gm) + 1
}

function nextAdrNumber(): number {
  if (!existsSync("docs/adr")) return 1
  const max = readdirSync("docs/adr")
    .map(file => file.match(/^ADR-(\d{3})/i)?.[1] ?? "0")
    .map(value => Number(value))
    .reduce((current, value) => Math.max(current, value), 0)
  return max + 1
}

function pad3(value: number): string {
  return String(value).padStart(3, "0")
}

function ensureWorkspaceFiles(
  state: ProjectState,
  surface: AddableSurface,
  workspace: string,
): void {
  const workspaceDir = join("apps", workspace)
  mkdirSync(workspaceDir, { recursive: true })

  const packagePath = join(workspaceDir, "package.json")
  if (!existsSync(packagePath)) {
    writeFileSync(
      packagePath,
      `${JSON.stringify(
        {
          name: `@${state.projectInfo.name || "project"}/${workspace}`,
          version: "0.1.0",
          private: true,
          type: "module",
          description: `${state.projectInfo.displayName || state.projectInfo.name || "Project"} ${workspace} workspace.`,
        },
        null,
        2,
      )}\n`,
    )
  }

  const readmePath = join(workspaceDir, "README.md")
  if (!existsSync(readmePath)) {
    writeFileSync(
      readmePath,
      `# ${state.projectInfo.displayName || state.projectInfo.name || "Project"} — ${workspace}\n\nWorkspace for the ${surfaceLabel(surface)} surface inside this monorepo.\n`,
    )
  }

  if (surface === "agent") {
    mkdirSync("skills/api-wrapper", { recursive: true })
    mkdirSync("packages/shared/api", { recursive: true })
    const apiReadmePath = "packages/shared/api/README.md"
    if (!existsSync(apiReadmePath)) {
      writeFileSync(
        apiReadmePath,
        `# Shared API wrappers\n\nAdd agent-facing service wrappers under this directory.\n`,
      )
    }
  }

  if (["web-app", "ios-app", "desktop"].includes(surface) && !existsSync("docs/design/DESIGN_SYSTEM.md")) {
    mkdirSync("docs/design", { recursive: true })
    writeFileSync(
      "docs/design/DESIGN_SYSTEM.md",
      "# DESIGN_SYSTEM\n\nGenerated placeholder. Add UI tokens, layouts, and review criteria before the first UI task is implemented.\n",
    )
  }
}

function ensurePrdSurfaceSection(
  surface: AddableSurface,
  workspace: string,
  milestoneNumber: number,
  featureNumber: number,
): void {
  writeManagedFile({
    path: "docs/prd/03-requirements.md",
    marker: `HARNESS:SURFACE:PRD:${workspace}`,
    content: `### Milestone ${milestoneNumber}: ${surfaceLabel(surface)} Expansion

#### F${pad3(featureNumber)}: ${surfaceLabel(surface)} Surface Onboarding
- **Description**: Add the \`${workspace}\` workspace inside the monorepo and prepare it for incremental delivery.
- **User story**: As the product grows, I want to add the ${surfaceLabel(surface)} surface in the same monorepo so all surfaces share one execution contract.
- **Acceptance criteria**:
  - [ ] \`apps/${workspace}/package.json\` exists
  - [ ] Architecture documents the \`${workspace}\` workspace
  - [ ] Progress/backlog includes the surface onboarding milestone
  - [ ] Follow-up milestones can build on the same monorepo instead of creating a new repo
- **Priority**: P1
- **Dependencies**: F001`,
  })
}

function ensureArchitectureSurfaceSection(surface: AddableSurface, workspace: string): void {
  writeManagedFile({
    path: "docs/architecture/02-project-structure.md",
    marker: `HARNESS:SURFACE:ARCH:${workspace}`,
    content: `### ${surfaceLabel(surface)} Workspace

- **Workspace**: \`apps/${workspace}\`
- **Purpose**: Host the ${surfaceLabel(surface)} surface inside the existing monorepo.
- **Expansion rule**: New surfaces are added as later milestones in the same monorepo, not as separate repos.`,
  })
}

function ensureAdrForSurface(surface: AddableSurface, workspace: string): void {
  if (!existsSync("docs/adr")) mkdirSync("docs/adr", { recursive: true })

  const slug = `${workspace}-surface`
  const existing = existsSync("docs/adr")
    ? readdirSync("docs/adr").find(file => file.includes(slug))
    : undefined

  if (existing) return

  const adrNumber = pad3(nextAdrNumber())
  const path = join("docs/adr", `ADR-${adrNumber}-add-${slug}.md`)
  writeFileSync(
    path,
    `# ADR-${adrNumber}: Add ${surfaceLabel(surface)} surface\n\n` +
      `- Status: Accepted\n` +
      `- Decision: Add \`apps/${workspace}\` inside the existing monorepo.\n` +
      `- Rationale: Keep all product surfaces under one execution contract, shared docs, and shared runtime.\n`,
  )
}

function nextTaskId(state: ProjectState): string {
  const current = state.execution.milestones
    .flatMap(milestone => milestone.tasks)
    .map(task => Number(task.id.replace(/^T/, "")))
    .reduce((max, value) => Math.max(max, value), 0)

  return `T${String(current + 1).padStart(3, "0")}`
}

function nextMilestoneId(state: ProjectState): string {
  const current = state.execution.milestones
    .map(milestone => Number(milestone.id.replace(/^M/, "")))
    .reduce((max, value) => Math.max(max, value), 0)

  return `M${current + 1}`
}

function taskForSurface(state: ProjectState, surface: AddableSurface, workspace: string, milestoneId: string): Task {
  return {
    affectedFiles: [`apps/${workspace}`, "docs/prd/03-requirements.md", "docs/architecture/02-project-structure.md"],
    checklist: createEmptyTaskChecklist(),
    dod: [
      `Create apps/${workspace} workspace scaffold`,
      "Document the new surface in PRD and Architecture",
      "Keep the work inside the same monorepo",
    ],
    id: nextTaskId(state),
    isUI: isUiProject([surface]),
    milestoneId,
    name: `${surfaceLabel(surface)} surface onboarding`,
    prdRef: "PRD#SurfaceExpansion",
    retryCount: 0,
    status: "PENDING",
    type: "TASK",
  }
}

function ensureExecutionMilestone(state: ProjectState, surface: AddableSurface, workspace: string): void {
  if (state.phase !== "EXECUTING" && state.execution.milestones.length === 0) return

  const branchSlug = slugify(`${workspace}-surface`)
  const existing = state.execution.milestones.find(
    milestone => milestone.branch === `milestone/${branchSlug}`,
  )
  if (existing) return

  const milestoneId = nextMilestoneId(state)
  const milestone: Milestone = {
    branch: `milestone/${branchSlug}`,
    id: milestoneId,
    name: `${surfaceLabel(surface)} Expansion`,
    status: "PENDING",
    tasks: [taskForSurface(state, surface, workspace, milestoneId)],
    worktreePath: `../${state.projectInfo.name || "project"}-${branchSlug}`,
  }

  state.execution.milestones.push(milestone)
  state.execution.allMilestonesComplete = false
}

export function addSurfaceToState(
  state: ProjectState,
  surfaceInput: string,
  preferredWorkspace?: string,
): { changed: boolean; state: ProjectState; surface: AddableSurface; workspace: string } {
  if (!isAddableSurface(surfaceInput)) {
    throw new Error(`Unsupported surface "${surfaceInput}". Use one of: web-app, ios-app, cli, agent, desktop.`)
  }

  const surface = surfaceInput
  const alreadyPresent = state.projectInfo.types.includes(surface)
  const defaultWorkspace = workspaceForSurface(surface)
  const workspace =
    alreadyPresent && preferredWorkspace && existsSync(join("apps", slugify(preferredWorkspace)))
      ? slugify(preferredWorkspace)
      : alreadyPresent && existsSync(join("apps", defaultWorkspace))
        ? defaultWorkspace
        : workspaceForSurface(surface, preferredWorkspace)

  const types = normalizeProjectTypes([...state.projectInfo.types, surface])

  ensureWorkspaceFiles(state, surface, workspace)
  ensureAdrForSurface(surface, workspace)
  ensurePrdSurfaceSection(surface, workspace, nextMilestoneNumber(), nextFeatureNumber())
  ensureArchitectureSurfaceSection(surface, workspace)

  state.projectInfo.types = types
  ensureExecutionMilestone(state, surface, workspace)

  return {
    changed: !alreadyPresent,
    state,
    surface,
    workspace,
  }
}

export function createApiWrapperService(
  state: ProjectState,
  serviceName: string,
  source: "manual" | "openapi",
  specPath?: string,
): { created: boolean; path: string } {
  if (!hasAgentSurface(state.projectInfo.types)) {
    throw new Error("This project does not include an agent surface yet. Add one with bun harness:add-surface --type agent.")
  }

  const service = slugify(serviceName)
  if (!service) {
    throw new Error("Please provide a non-empty service name.")
  }

  if (source === "openapi" && !specPath) {
    throw new Error("When --source=openapi is used, provide --spec <path>.")
  }

  const serviceDir = join("packages/shared/api", service)
  mkdirSync(serviceDir, { recursive: true })

  const files = [
    {
      path: join(serviceDir, "README.md"),
      content:
        `# ${service}\n\n` +
        `Source: ${source}\n` +
        `${specPath ? `Spec: ${specPath}\n` : ""}\n` +
        `This wrapper centralizes auth, retries, and payload shaping for the ${service} service.\n`,
    },
    {
      path: join(serviceDir, "index.ts"),
      content:
        `export type ${service.replace(/(^|-)([a-z])/g, (_, __, letter) => letter.toUpperCase())}Request = Record<string, unknown>\n` +
        `export type ${service.replace(/(^|-)([a-z])/g, (_, __, letter) => letter.toUpperCase())}Response = Record<string, unknown>\n\n` +
        `export async function call${service.replace(/(^|-)([a-z])/g, (_, __, letter) => letter.toUpperCase())}(\n` +
        `  request: ${service.replace(/(^|-)([a-z])/g, (_, __, letter) => letter.toUpperCase())}Request,\n` +
        `): Promise<${service.replace(/(^|-)([a-z])/g, (_, __, letter) => letter.toUpperCase())}Response> {\n` +
        `  void request\n` +
        `  throw new Error("Wrapper not implemented yet.")\n` +
        `}\n`,
    },
    {
      path: join(serviceDir, "schema.ts"),
      content:
        `export const ${service.replace(/-/g, "_")}_schema = {\n` +
        `  source: "${source}",\n` +
        `  spec: ${specPath ? `"${specPath.replace(/\\/g, "/")}"` : "null"},\n` +
        `}\n`,
    },
  ]

  let created = false
  for (const file of files) {
    if (!existsSync(file.path)) {
      writeFileSync(file.path, file.content)
      created = true
    }
  }

  return { created, path: serviceDir.replace(/\\/g, "/") }
}

import { existsSync } from "fs"
import type { Milestone, ProjectState, ProjectType, Task } from "../types"
import { initState, readState, writeState } from "./state-core"
import { isUiProject, PRD_DIR, PRD_PATH, readDocument, STATE_PATH } from "./shared"
import { createEmptyTaskChecklist } from "./task-checklist"

type ParsedTaskSpec = {
  affectedFiles: string[]
  dod: string[]
  isUI: boolean
  milestoneId: string
  name: string
  prdRef: string
}

type ParsedMilestoneSpec = {
  branch: string
  id: string
  name: string
  tasks: ParsedTaskSpec[]
  worktreePath: string
}

function slugify(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .replace(/-{2,}/g, "-")
}

function inferTaskFiles(isUI: boolean): string[] {
  return isUI
    ? ["src/app", "src/services", "src/types", "docs/design/DESIGN_SYSTEM.md", "tests"]
    : ["src/types", "src/config", "src/lib", "src/services", "tests"]
}

function inferUiTask(text: string, projectTypes: ProjectType[]): boolean {
  if (!isUiProject(projectTypes)) return false
  return /(ui|page|screen|layout|component|design|dashboard|form|login|settings|profile|navbar|modal|table)/i.test(
    text,
  )
}

function parsePrdBacklogSpecs(state: ProjectState): ParsedMilestoneSpec[] {
  const content = readDocument(PRD_PATH, PRD_DIR)
  if (!content) {
    throw new Error("docs/prd/ or docs/PRD.md not found. Generate PRD before running --from-prd.")
  }

  const lines = content.split(/\r?\n/)
  const milestones: ParsedMilestoneSpec[] = []
  let currentMilestone: ParsedMilestoneSpec | null = null
  let currentFeature:
    | {
        featureId: string
        name: string
        body: string[]
        dod: string[]
      }
    | null = null
  const flushFeature = () => {
    if (!currentMilestone || !currentFeature) return

    const taskText = [currentMilestone.name, currentFeature.name, ...currentFeature.body, ...currentFeature.dod].join(" ")
    const taskIsUi = inferUiTask(taskText, state.projectInfo.types)

    currentMilestone.tasks.push({
      name: currentFeature.name,
      prdRef: `PRD#F${currentFeature.featureId}`,
      milestoneId: currentMilestone.id,
      dod: currentFeature.dod.length > 0 ? currentFeature.dod : ["Meet PRD acceptance criteria"],
      isUI: taskIsUi,
      affectedFiles: inferTaskFiles(taskIsUi),
    })

    currentFeature = null
  }

  const flushMilestone = () => {
    flushFeature()
    if (!currentMilestone) return
    milestones.push(currentMilestone)
    currentMilestone = null
  }

  for (const line of lines) {
    const milestoneMatch = line.match(/^###\s+Milestone\s+(\d+)[：:]\s*(.+)$/)
    if (milestoneMatch) {
      flushMilestone()
      const milestoneNumber = milestoneMatch[1]
      const milestoneName = milestoneMatch[2].trim()
      currentMilestone = {
        id: `M${milestoneNumber}`,
        name: milestoneName,
        branch: `milestone/m${milestoneNumber}-${slugify(milestoneName || "milestone")}`,
        worktreePath: `../${state.projectInfo.name || "project"}-m${milestoneNumber}`,
        tasks: [],
      }
      continue
    }

    const featureMatch = line.match(/^####\s+F(\d{3})[：:]\s*(.+)$/)
    if (featureMatch && currentMilestone) {
      flushFeature()
      currentFeature = {
        featureId: featureMatch[1],
        name: featureMatch[2].trim(),
        body: [],
        dod: [],
      }
      continue
    }

    if (!currentFeature) continue

    const dodMatch = line.match(/^\s*-\s*\[\s*\]\s*(.+)$/)
    if (dodMatch) {
      currentFeature.dod.push(dodMatch[1].trim())
      continue
    }

    const trimmed = line.trim()
    if (trimmed.length > 0) {
      currentFeature.body.push(trimmed)
    }
  }

  flushMilestone()

  if (milestones.length === 0) {
      milestones.push({
        id: "M1",
        name: "Foundation",
        branch: "milestone/m1-foundation",
        worktreePath: `../${state.projectInfo.name || "project"}-m1`,
        tasks: [
          {
            name: "Foundation setup",
            prdRef: "PRD#F001",
            milestoneId: "M1",
            dod: ["Complete foundational project initialization"],
            isUI: isUiProject(state.projectInfo.types),
            affectedFiles: inferTaskFiles(isUiProject(state.projectInfo.types)),
          },
        ],
      })
  }

  return milestones
}

function taskNumber(taskId: string): number {
  const match = taskId.match(/^T(\d+)$/)
  return match ? Number.parseInt(match[1], 10) : 0
}

function nextTaskId(nextNumber: number): string {
  return `T${String(nextNumber).padStart(3, "0")}`
}

function createTaskFromSpec(spec: ParsedTaskSpec, taskId: string): Task {
  return {
    id: taskId,
    name: spec.name,
    type: "TASK",
    status: "PENDING",
    prdRef: spec.prdRef,
    milestoneId: spec.milestoneId,
    dod: [...spec.dod],
    isUI: spec.isUI,
    affectedFiles: [...spec.affectedFiles],
    retryCount: 0,
    checklist: createEmptyTaskChecklist(),
  }
}

function buildMilestonesFromSpecs(specs: ParsedMilestoneSpec[]): Milestone[] {
  let taskCounter = 1

  return specs.map(spec => ({
    id: spec.id,
    name: spec.name,
    branch: spec.branch,
    worktreePath: spec.worktreePath,
    status: "PENDING",
    tasks: spec.tasks.map(task => createTaskFromSpec(task, nextTaskId(taskCounter++))),
  }))
}

function activateNextAvailableTask(milestones: Milestone[]): {
  currentMilestone: string
  currentTask: string
  currentWorktree: string
} {
  const activeTask = milestones
    .flatMap(milestone => milestone.tasks.map(task => ({ milestone, task })))
    .find(entry => entry.task.status === "IN_PROGRESS")

  if (activeTask) {
    activeTask.task.startedAt = activeTask.task.startedAt ?? new Date().toISOString()
    if (activeTask.milestone.status === "PENDING") {
      activeTask.milestone.status = "IN_PROGRESS"
    }
    return {
      currentMilestone: activeTask.milestone.id,
      currentTask: activeTask.task.id,
      currentWorktree: activeTask.milestone.worktreePath,
    }
  }

  for (const milestone of milestones) {
    const nextTask = milestone.tasks.find(task => task.status === "PENDING")
    if (!nextTask) continue

    nextTask.status = "IN_PROGRESS"
    nextTask.startedAt = nextTask.startedAt ?? new Date().toISOString()
    if (milestone.status === "PENDING") {
      milestone.status = "IN_PROGRESS"
    }
    return {
      currentMilestone: milestone.id,
      currentTask: nextTask.id,
      currentWorktree: milestone.worktreePath,
    }
  }

  return { currentMilestone: "", currentTask: "", currentWorktree: "" }
}

function hasOpenMilestones(milestones: Milestone[]): boolean {
  return milestones.some(milestone => !["MERGED", "COMPLETE"].includes(milestone.status))
}

export function deriveExecutionFromPrd(baseState: ProjectState): ProjectState {
  const milestones = buildMilestonesFromSpecs(parsePrdBacklogSpecs(baseState))
  const pointers = activateNextAvailableTask(milestones)

  return {
    ...baseState,
    phase:
      baseState.phase === "VALIDATING" || baseState.phase === "COMPLETE"
        ? baseState.phase
        : "EXECUTING",
    execution: {
      currentMilestone: pointers.currentMilestone,
      currentTask: pointers.currentTask,
      currentWorktree: pointers.currentWorktree,
      milestones,
      allMilestonesComplete: false,
    },
    docs: {
      ...baseState.docs,
      prd: {
        ...baseState.docs.prd,
        exists: true,
        milestoneCount: milestones.length,
      },
      progress: {
        ...baseState.docs.progress,
        exists: true,
        lastUpdated: new Date().toISOString(),
      },
    },
  }
}

export function syncExecutionFromPrd(baseState: ProjectState): {
  addedMilestones: number
  addedTasks: number
  state: ProjectState
} {
  const parsedMilestones = parsePrdBacklogSpecs(baseState)
  const existingMilestones = baseState.execution.milestones
  const existingMilestoneMap = new Map(existingMilestones.map(milestone => [milestone.id, milestone]))
  const highestTaskNumber = existingMilestones
    .flatMap(milestone => milestone.tasks)
    .reduce((highest, task) => Math.max(highest, taskNumber(task.id)), 0)

  let nextTaskNumberValue = highestTaskNumber
  let addedMilestones = 0
  let addedTasks = 0

  const mergedMilestones = parsedMilestones.map(spec => {
    const existingMilestone = existingMilestoneMap.get(spec.id)
    const existingTaskMap = new Map(existingMilestone?.tasks.map(task => [task.prdRef, task]) ?? [])
    const parsedPrdRefs = new Set(spec.tasks.map(task => task.prdRef))

    if (existingMilestone && ["MERGED", "COMPLETE"].includes(existingMilestone.status)) {
      const appendedScope = spec.tasks.filter(task => !existingTaskMap.has(task.prdRef))
      if (appendedScope.length > 0) {
        throw new Error(
          `Milestone ${spec.id} is already ${existingMilestone.status}. Add new scope as a new milestone instead of modifying a merged milestone.`,
        )
      }
    }

    const tasks = spec.tasks.map(taskSpec => {
      const existingTask = existingTaskMap.get(taskSpec.prdRef)
      if (existingTask) {
        return {
          ...existingTask,
          name: taskSpec.name,
          prdRef: taskSpec.prdRef,
          milestoneId: spec.id,
          dod: [...taskSpec.dod],
          isUI: taskSpec.isUI,
          affectedFiles: [...taskSpec.affectedFiles],
        }
      }

      addedTasks++
      nextTaskNumberValue += 1
      return createTaskFromSpec(taskSpec, nextTaskId(nextTaskNumberValue))
    })

    const orphanTasks = existingMilestone?.tasks.filter(task => !parsedPrdRefs.has(task.prdRef)) ?? []
    const milestone: Milestone = existingMilestone
      ? {
          ...existingMilestone,
          name: spec.name,
          branch: existingMilestone.branch || spec.branch,
          worktreePath: existingMilestone.worktreePath || spec.worktreePath,
          tasks: [...tasks, ...orphanTasks],
        }
      : {
          id: spec.id,
          name: spec.name,
          branch: spec.branch,
          worktreePath: spec.worktreePath,
          status: "PENDING",
          tasks,
        }

    if (!existingMilestone) {
      addedMilestones++
    }

    return milestone
  })

  const parsedIds = new Set(parsedMilestones.map(milestone => milestone.id))
  const orphanMilestones = existingMilestones.filter(milestone => !parsedIds.has(milestone.id))
  const milestones = [...mergedMilestones, ...orphanMilestones]
  const pointers = activateNextAvailableTask(milestones)
  const shouldReopenExecution = hasOpenMilestones(milestones)

  const nextState: ProjectState = {
    ...baseState,
    phase:
      shouldReopenExecution && ["VALIDATING", "COMPLETE"].includes(baseState.phase)
        ? "EXECUTING"
        : baseState.phase,
    execution: {
      currentMilestone: pointers.currentMilestone,
      currentTask: pointers.currentTask,
      currentWorktree: pointers.currentWorktree,
      milestones,
      allMilestonesComplete: !shouldReopenExecution && milestones.length > 0,
    },
    docs: {
      ...baseState.docs,
      prd: {
        ...baseState.docs.prd,
        exists: true,
        milestoneCount: Math.max(baseState.docs.prd.milestoneCount, parsedMilestones.length),
      },
      progress: {
        ...baseState.docs.progress,
        exists: true,
        lastUpdated: new Date().toISOString(),
      },
    },
  }

  return {
    addedMilestones,
    addedTasks,
    state: nextState,
  }
}

export function bootstrapExecutionFromPrd(): ProjectState {
  const baseState = existsSync(STATE_PATH) ? readState() : initState({})
  return writeState(deriveExecutionFromPrd(baseState))
}

export function syncExecutionBacklogFromPrd(): {
  addedMilestones: number
  addedTasks: number
  state: ProjectState
} {
  const baseState = existsSync(STATE_PATH) ? readState() : initState({})
  const result = syncExecutionFromPrd(baseState)
  return {
    ...result,
    state: writeState(result.state),
  }
}

import { existsSync, readFileSync, writeFileSync } from "fs"
import type { ProjectState } from "../types"

type EnvBlock = {
  block: string
  id: string
}

function buildBlocks(state: ProjectState): EnvBlock[] {
  const blocks: EnvBlock[] = [
    {
      id: "NODE_ENV",
      block: `# .env.local
# Local-only environment scaffold generated by Harness.
# Fill values milestone by milestone as real integrations are implemented.
# Do not commit this file.

# Core
NODE_ENV=development
APP_URL=http://localhost:3000
DEPLOY_TARGET=
DEPLOY_ENV=development`,
    },
  ]

  if (state.projectInfo.types.includes("web-app")) {
    blocks.push({
      id: "WEB_DEV_PORT",
      block: `# Web surface
WEB_DEV_PORT=3000
WEB_PUBLIC_URL=http://localhost:3000`,
    })
  }

  if (state.projectInfo.types.includes("ios-app")) {
    blocks.push({
      id: "IOS_BUNDLE_ID",
      block: `# iOS surface
IOS_BUNDLE_ID=com.example.${state.projectInfo.name || "app"}
IOS_APP_SCHEME=${(state.projectInfo.displayName || state.projectInfo.name || "App").replace(/\s+/g, "")}`,
    })
  }

  if (state.projectInfo.types.includes("cli")) {
    blocks.push({
      id: "CLI_BINARY_NAME",
      block: `# CLI surface
CLI_BINARY_NAME=${state.projectInfo.name || "app-cli"}`,
    })
  }

  if (state.projectInfo.types.includes("agent")) {
    blocks.push({
      id: "AGENT_PORT",
      block: `# Agent surface
AGENT_PORT=8787
AGENT_SKILL_CATALOG=./SKILLS.md
AGENT_API_WRAPPER_DIR=packages/shared/api`,
    })
  }

  if (state.projectInfo.types.includes("desktop")) {
    blocks.push({
      id: "DESKTOP_DEV_PORT",
      block: `# Desktop surface
DESKTOP_DEV_PORT=3001`,
    })
  }

  if (["openai", "both", "vercel-ai-sdk"].includes(state.projectInfo.aiProvider)) {
    blocks.push({
      id: "OPENAI_API_KEY",
      block: `# OpenAI
OPENAI_API_KEY=`,
    })
  }

  if (["anthropic", "both"].includes(state.projectInfo.aiProvider)) {
    blocks.push({
      id: "ANTHROPIC_API_KEY",
      block: `# Anthropic
ANTHROPIC_API_KEY=`,
    })
  }

  if (state.projectInfo.aiProvider === "vercel-ai-sdk") {
    blocks.push({
      id: "AI_GATEWAY_API_KEY",
      block: `# Vercel AI SDK / Gateway
AI_GATEWAY_API_KEY=`,
    })
  }

  blocks.push({
    id: "DATABASE_URL",
    block: `# Optional data layer placeholders
DATABASE_URL=
AUTH_SECRET=
REDIS_URL=`,
  })

  return blocks
}

export function ensureEnvLocalSkeleton(state: ProjectState): { changed: boolean; created: boolean } {
  const path = ".env.local"
  const blocks = buildBlocks(state)

  if (!existsSync(path)) {
    writeFileSync(path, `${blocks.map(block => block.block).join("\n\n")}\n`)
    return { changed: true, created: true }
  }

  let current = readFileSync(path, "utf-8")
  let changed = false

  for (const block of blocks) {
    if (current.includes(`${block.id}=`)) continue
    current = `${current.trimEnd()}\n\n${block.block}\n`
    changed = true
  }

  if (changed) {
    writeFileSync(path, current)
  }

  return { changed, created: false }
}

import type { Milestone, Phase, ProjectState, Task, TaskChecklist } from "../types"
import { formatAtomicCommitFailure, inspectAtomicTaskCommit } from "./atomic-commit"
import { readState, writeState } from "./state-core"
import { mergeTaskChecklist } from "./task-checklist"

function findTaskLocation(state: ProjectState, taskId: string): { milestone: Milestone; task: Task } | null {
  for (const milestone of state.execution.milestones) {
    const task = milestone.tasks.find(candidate => candidate.id === taskId)
    if (task) return { milestone, task }
  }
  return null
}

function preserveActiveTask(state: ProjectState): boolean {
  if (!state.execution.currentTask) return false

  const location = findTaskLocation(state, state.execution.currentTask)
  if (!location || location.task.status !== "IN_PROGRESS") {
    return false
  }

  location.task.startedAt = location.task.startedAt ?? new Date().toISOString()
  state.execution.currentMilestone = location.milestone.id
  state.execution.currentWorktree = location.milestone.worktreePath
  if (location.milestone.status === "PENDING") {
    location.milestone.status = "IN_PROGRESS"
  }
  return true
}

function activateNextTask(state: ProjectState): void {
  if (preserveActiveTask(state)) {
    return
  }

  for (const milestone of state.execution.milestones) {
    const nextTask = milestone.tasks.find(task => task.status === "PENDING")
    if (!nextTask) continue

    nextTask.startedAt = nextTask.startedAt ?? new Date().toISOString()
    milestone.status = milestone.status === "PENDING" ? "IN_PROGRESS" : milestone.status
    nextTask.status = "IN_PROGRESS"
    state.execution.currentMilestone = milestone.id
    state.execution.currentTask = nextTask.id
    state.execution.currentWorktree = milestone.worktreePath
    return
  }

  state.execution.currentMilestone = ""
  state.execution.currentTask = ""
  state.execution.currentWorktree = ""
}

function refreshMilestoneStatuses(state: ProjectState): void {
  for (const milestone of state.execution.milestones) {
    const allFinished = milestone.tasks.every(
      task => task.status === "DONE" || task.status === "SKIPPED",
    )
    const hasWorkStarted = milestone.tasks.some(task =>
      ["IN_PROGRESS", "DONE", "BLOCKED"].includes(task.status),
    )

    if (allFinished) {
      milestone.status = milestone.status === "MERGED" ? "MERGED" : "REVIEW"
      milestone.completedAt = milestone.completedAt ?? new Date().toISOString()
    } else if (hasWorkStarted) {
      milestone.status = "IN_PROGRESS"
    } else if (milestone.status !== "COMPLETE" && milestone.status !== "MERGED") {
      milestone.status = "PENDING"
    }
  }
}

export function completeTask(taskId: string, commitHash: string): ProjectState {
  const state = readState()
  const location = findTaskLocation(state, taskId)
  if (!location) throw new Error(`Task ${taskId} not found`)

  const atomicCommit = inspectAtomicTaskCommit(state, taskId, commitHash)
  if (!atomicCommit.ok) {
    throw new Error(formatAtomicCommitFailure(taskId, atomicCommit))
  }

  location.task.status = "DONE"
  location.task.commitHash = atomicCommit.commitHash
  location.task.completedAt = new Date().toISOString()
  if (location.task.type === "TASK") {
    const checklist = location.task.checklist as Partial<TaskChecklist> | undefined
    location.task.checklist = mergeTaskChecklist(checklist, {
      prdDodMet: true,
      atomicCommitDone: atomicCommit.ok,
      progressUpdated: true,
    })
  }

  if (state.execution.currentTask === taskId) {
    state.execution.currentTask = ""
  }

  refreshMilestoneStatuses(state)
  activateNextTask(state)

  const updated = writeState(state)
  console.log(`✅ Task ${taskId} marked DONE (commit: ${atomicCommit.commitHash})`)
  return updated
}

export function blockTask(taskId: string, reason: string): ProjectState {
  const state = readState()
  const location = findTaskLocation(state, taskId)
  if (!location) throw new Error(`Task ${taskId} not found`)

  location.task.status = "BLOCKED"
  location.task.retryCount = (location.task.retryCount ?? 0) + 1
  location.task.blockedReason = reason
  location.task.blockedAt = new Date().toISOString()
  if (location.task.type === "TASK") {
    const checklist = location.task.checklist as Partial<TaskChecklist> | undefined
    location.task.checklist = mergeTaskChecklist(checklist, {
      progressUpdated: true,
    })
  }

  if (state.execution.currentTask === taskId) {
    state.execution.currentTask = ""
  }

  refreshMilestoneStatuses(state)
  activateNextTask(state)

  const updated = writeState(state)
  console.log(`⚠️  Task ${taskId} BLOCKED: ${reason}`)
  return updated
}

export function completeMilestone(milestoneId: string, mergeCommit: string): ProjectState {
  const state = readState()
  const milestone = state.execution.milestones.find(m => m.id === milestoneId)
  if (!milestone) throw new Error(`Milestone ${milestoneId} not found`)
  if (milestone.status !== "REVIEW") {
    throw new Error(`Milestone ${milestoneId} is ${milestone.status}, expected REVIEW`)
  }

  milestone.status = "MERGED"
  milestone.mergeCommit = mergeCommit
  milestone.completedAt = milestone.completedAt ?? new Date().toISOString()

  if (state.execution.currentMilestone === milestoneId) {
    state.execution.currentMilestone = ""
    state.execution.currentTask = ""
    state.execution.currentWorktree = ""
  }

  refreshMilestoneStatuses(state)
  activateNextTask(state)

  const updated = writeState(state)
  console.log(`✅ Milestone ${milestoneId} marked MERGED (commit: ${mergeCommit})`)
  return updated
}

export function advancePhase(newPhase: Phase): ProjectState {
  const state = readState()
  state.phase = newPhase
  const updated = writeState(state)
  console.log(`📍 Phase advanced to: ${newPhase}`)
  return updated
}

