import type { ProjectState } from "../../types"
import { runBun } from "../validation/helpers"
import { loadState, saveState, syncStateFromFilesystem } from "../validation/state"
import { dispatch } from "./dispatcher"
import { getPhaseReadiness } from "./phase-readiness"

const AUTOFLOW_MAX_STEPS = 12

function readRuntimeState(): ProjectState {
  const loaded = loadState(true)
  const state = syncStateFromFilesystem(loaded!)
  saveState(state)
  return state
}

function logStep(message: string): void {
  console.log(`• ${message}`)
}

async function runCommand(label: string, args: string[]): Promise<boolean> {
  logStep(label)
  const result = await runBun(args)
  if (result.ok) return true

  if (result.output.trim()) {
    console.error(result.output.trim())
  }
  return false
}

async function tryAdvance(): Promise<boolean> {
  return runCommand("bun harness:advance", ["run", "harness:advance"])
}

function stopAtBoundary(state: ProjectState): number {
  const next = dispatch(state)
  const readiness = getPhaseReadiness(state)
  console.log(`\nAutoflow stopped at phase ${state.phase}.`)
  if (readiness.missingOutputs.length > 0) {
    console.log("Missing outputs:")
    for (const item of readiness.missingOutputs) {
      console.log(`- ${item}`)
    }
  }
  if (next.type === "agent" && next.agentId) {
    console.log(`Next agent: ${next.agentId}`)
  } else {
    console.log(next.message)
  }
  return 0
}

function getReviewMilestone(state: ProjectState) {
  return state.execution.milestones.find(milestone => milestone.status === "REVIEW")
}

export async function runAutoflow(): Promise<number> {
  for (let step = 0; step < AUTOFLOW_MAX_STEPS; step++) {
    const state = readRuntimeState()
    const readiness = getPhaseReadiness(state)

    switch (state.phase) {
      case "DISCOVERY":
      case "MARKET_RESEARCH":
      case "TECH_STACK": {
        if (!readiness.ready) {
          return stopAtBoundary(state)
        }
        if (!(await tryAdvance())) {
          return stopAtBoundary(state)
        }
        continue
      }

      case "PRD_ARCH": {
        if (!readiness.ready) {
          return stopAtBoundary(state)
        }
        if (!(await tryAdvance())) {
          return stopAtBoundary(state)
        }
        continue
      }

      case "SCAFFOLD": {
        if (!readiness.ready) {
          return stopAtBoundary(state)
        }
        if (!(await runCommand("bun install", ["install"]))) return 1
        if (!(await runCommand("bun harness:env", ["run", "harness:env"]))) return 1
        if (!(await runCommand("bun .harness/init.ts --from-prd", [".harness/init.ts", "--from-prd"]))) return 1
        if (!(await runCommand("bun harness:validate --phase EXECUTING", ["run", "harness:validate", "--phase", "EXECUTING"]))) return 1
        return stopAtBoundary(readRuntimeState())
      }

      case "EXECUTING": {
        const reviewMilestone = getReviewMilestone(state)
        if (reviewMilestone) {
          if (
            !(await runCommand(
              `bun harness:merge-milestone ${reviewMilestone.id} (auto closeout + compact)`,
              ["run", "harness:merge-milestone", reviewMilestone.id],
            ))
          ) {
            return stopAtBoundary(readRuntimeState())
          }
          continue
        }

        if (!state.execution.allMilestonesComplete) {
          return stopAtBoundary(state)
        }

        if (!(await tryAdvance())) return 1
        continue
      }

      case "VALIDATING": {
        if (!(await tryAdvance())) {
          return stopAtBoundary(state)
        }
        continue
      }

      case "COMPLETE": {
        if (!(await runCommand("bun harness:compact:status", ["run", "harness:compact:status"]))) return 1
        return stopAtBoundary(state)
      }
    }
  }

  console.error("Autoflow reached the maximum number of steps without settling.")
  return 1
}

import type {
  AgentId,
  AgentPacketMilestone,
  AgentPacketTask,
  AgentTaskPacket,
  Milestone,
  ProjectState,
  Task,
} from "../../types"
import { getAgentEntry } from "./agent-registry"
import { getAgentMaterialPolicy } from "./material-policy"
import { getPhaseReadiness } from "./phase-readiness"

function getCurrentMilestone(state: ProjectState): Milestone | undefined {
  return state.execution.milestones.find(m => m.id === state.execution.currentMilestone)
}

function getCurrentTask(state: ProjectState): Task | undefined {
  return state.execution.milestones
    .flatMap(m => m.tasks)
    .find(t => t.id === state.execution.currentTask)
}

function serializeMilestone(milestone?: Milestone): AgentPacketMilestone | undefined {
  if (!milestone) return undefined
  return {
    id: milestone.id,
    name: milestone.name,
    status: milestone.status,
  }
}

function serializeTask(task?: Task): AgentPacketTask | undefined {
  if (!task) return undefined
  return {
    affectedFiles: [...task.affectedFiles],
    id: task.id,
    isUI: task.isUI,
    name: task.name,
    prdRef: task.prdRef,
    retryCount: task.retryCount,
    status: task.status,
    type: task.type,
  }
}

function formatValidationCommand(agentId: AgentId, state: ProjectState): string {
  const task = getCurrentTask(state)
  const milestone = getCurrentMilestone(state)

  switch (agentId) {
    case "project-discovery":
      return "bun harness:validate --phase MARKET_RESEARCH"
    case "prd-architect":
      return "bun harness:validate --phase SCAFFOLD"
    case "scaffold-generator":
      return "bun harness:validate --phase EXECUTING"
    case "context-compactor":
      return "bun harness:validate --phase COMPLETE"
    case "execution-engine":
    case "design-reviewer":
    case "code-reviewer":
      return task ? `bun harness:validate --task ${task.id}` : "bun harness:validate"
    case "harness-validator":
      return milestone
        ? `bun harness:validate --milestone ${milestone.id}`
        : "bun harness:validate"
    default:
      return `bun harness:validate --phase ${state.phase}`
  }
}

function agentOwnsCurrentPhase(agentId: AgentId, phase: ProjectState["phase"]): boolean {
  switch (phase) {
    case "DISCOVERY":
      return agentId === "project-discovery"
    case "MARKET_RESEARCH":
      return agentId === "market-research"
    case "TECH_STACK":
      return agentId === "tech-stack-advisor"
    case "PRD_ARCH":
      return agentId === "prd-architect"
    case "SCAFFOLD":
      return agentId === "scaffold-generator"
    case "VALIDATING":
      return agentId === "harness-validator"
    case "COMPLETE":
      return agentId === "context-compactor"
    default:
      return false
  }
}

function buildAfterCompletion(agentId: AgentId, state: ProjectState, validationCmd: string): string[] {
  const task = getCurrentTask(state)

  if (agentId === "project-discovery") {
    return [
      `Validation: ${validationCmd}`,
      "Advance: bun harness:advance",
      "Next: Re-run orchestrator to dispatch Market Research.",
      "  bun .harness/orchestrator.ts",
    ]
  }

  if (agentId === "prd-architect") {
    return [
      `Validation: ${validationCmd}`,
      "Advance: bun harness:advance",
      "Next: Re-run orchestrator to dispatch Scaffold Generator.",
      "  bun .harness/orchestrator.ts",
    ]
  }

  if (agentId === "scaffold-generator") {
    return [
      "Install deps: bun install",
      "Advance: bun harness:advance",
      `Validation: ${validationCmd}`,
      "Next: Re-run orchestrator to dispatch the next runtime agent.",
      "  bun .harness/orchestrator.ts",
    ]
  }

  if (agentId === "harness-validator") {
    return [
      `Validation: ${validationCmd}`,
      "Advance: bun harness:advance",
      "Next: Re-run orchestrator to dispatch final closeout.",
      "  bun .harness/orchestrator.ts",
    ]
  }

  if (agentId === "context-compactor") {
    return [
      `Validation: ${validationCmd}`,
      "Closeout: bun harness:compact --status",
      "Project lifecycle is complete. Archive or clear session context if needed.",
    ]
  }

  if (agentId === "frontend-designer") {
    return [
      `Validation: ${validationCmd}`,
      "Next: Re-run orchestrator to dispatch Execution Engine for implementation.",
      "  bun .harness/orchestrator.ts",
    ]
  }

  if (agentId === "design-reviewer") {
    const lines = [
      `Validation: ${validationCmd}`,
      "If ✅ passed: proceed to Atomic Commit.",
      "  Commit message must include the current Task-ID, current PRD mapping, and: Design Review: ✅",
    ]
    if (task) {
      lines.push(`  State update: completeTask("${task.id}", "<commitHash>") from .harness/init.ts`)
    }
    lines.push("If ❌ failed: fix issues, re-run self-validation, then:")
    lines.push("  bun .harness/orchestrator.ts --review")
    return lines
  }

  if (agentId === "code-reviewer") {
    const lines = [
      `Validation: ${validationCmd}`,
      "If ✅ passed: proceed to Atomic Commit.",
      "  Commit message must include the current Task-ID, current PRD mapping, and: Code Review: ✅",
    ]
    if (task) {
      lines.push(`  State update: completeTask("${task.id}", "<commitHash>") from .harness/init.ts`)
    }
    lines.push("If ❌ failed: fix issues, re-run self-validation, then:")
    lines.push("  bun .harness/orchestrator.ts --code-review")
    return lines
  }

  if (task) {
    const lines = [
      `Validation: ${validationCmd}`,
      "Atomic Commit: create exactly one HEAD commit for this task, including the current Task-ID and PRD mapping.",
      `State update: completeTask("${task.id}", "<commitHash>") from .harness/init.ts`,
    ]
    if (task.isUI) {
      lines.push("UI Task: After self-validation passes, run Design Review:")
      lines.push("  bun .harness/orchestrator.ts --review")
    }
    return lines
  }

  return [`Validation: ${validationCmd}`]
}

export function buildAgentTaskPacket(agentId: AgentId, state: ProjectState): AgentTaskPacket {
  const entry = getAgentEntry(agentId)
  if (!entry) {
    throw new Error(`Agent "${agentId}" not found in registry.`)
  }

  const milestone = getCurrentMilestone(state)
  const task = getCurrentTask(state)
  const validationCmd = formatValidationCommand(agentId, state)
  const policy = getAgentMaterialPolicy(agentId, state)
  const phaseReadiness = getPhaseReadiness(state)
  const phaseOutputs = agentOwnsCurrentPhase(agentId, state.phase)
    ? phaseReadiness
    : { missingOutputs: [], requiredOutputs: [] }

  return {
    agentId,
    agentName: entry.name,
    afterCompletion: buildAfterCompletion(agentId, state, validationCmd),
    currentMilestone: serializeMilestone(milestone),
    currentTask: serializeTask(task),
    inlineConstraints: [...policy.inlineConstraints],
    missingOutputs: [...phaseOutputs.missingOutputs],
    optionalRefs: [...policy.optionalRefs],
    phase: state.phase,
    requiredOutputs: [...phaseOutputs.requiredOutputs],
    requiredRefs: [...policy.requiredRefs],
    specPath: entry.specPath,
    taskDod: task ? [...task.dod] : [],
    validationCommand: validationCmd,
    worktree: state.execution.currentWorktree || undefined,
  }
}

export function renderAgentTaskPacket(packet: AgentTaskPacket): string {
  const lines: string[] = []

  lines.push(`${"═".repeat(50)}`)
  lines.push("  Harness Orchestrator")
  lines.push(`${"═".repeat(50)}`)
  lines.push("")
  lines.push(`Agent: ${packet.agentName}`)
  lines.push(`Spec: ${packet.specPath}`)
  lines.push(`Packet Mode: selective`)
  lines.push("")

  lines.push(`${"─".repeat(40)} Inline Context`)
  lines.push(`Phase: ${packet.phase}`)
  if (packet.currentMilestone) {
    lines.push(
      `Milestone: ${packet.currentMilestone.id} — ${packet.currentMilestone.name} (${packet.currentMilestone.status})`,
    )
  }
  if (packet.currentTask) {
    lines.push(
      `Task: ${packet.currentTask.id} — ${packet.currentTask.name} (${packet.currentTask.status})`,
    )
    lines.push(`Task Type: ${packet.currentTask.type}`)
    lines.push(`PRD Ref: ${packet.currentTask.prdRef}`)
    lines.push(`UI Task: ${packet.currentTask.isUI ? "yes" : "no"}`)
    if (packet.currentTask.affectedFiles.length > 0) {
      lines.push(`Affected Files: ${packet.currentTask.affectedFiles.join(", ")}`)
    }
    if (packet.currentTask.retryCount >= 3) {
      lines.push(
        `⚠️  Task has failed ${packet.currentTask.retryCount} times. Please pause and notify the user. See agents/orchestrator.md:88`,
      )
    }
  }
  if (packet.worktree) {
    lines.push(`Worktree: ${packet.worktree}`)
  }
  lines.push(`Validation Gate: ${packet.validationCommand}`)
  lines.push("")

  if (packet.requiredOutputs.length > 0) {
    lines.push(`${"─".repeat(40)} Phase Outputs`)
    for (const item of packet.requiredOutputs) {
      const marker = packet.missingOutputs.includes(item) ? "[ ]" : "[x]"
      lines.push(`- ${marker} ${item}`)
    }
    lines.push("")
  }

  lines.push(`${"─".repeat(40)} Required Refs`)
  for (const ref of packet.requiredRefs) {
    lines.push(`- ${ref}`)
  }
  lines.push("")

  if (packet.optionalRefs.length > 0) {
    lines.push(`${"─".repeat(40)} Optional Refs`)
    for (const ref of packet.optionalRefs) {
      lines.push(`- ${ref}`)
    }
    lines.push("")
  }

  lines.push(`${"─".repeat(40)} Core Constraints`)
  for (const constraint of packet.inlineConstraints) {
    lines.push(`- ${constraint}`)
  }
  lines.push("")

  if (packet.taskDod.length > 0) {
    lines.push(`${"─".repeat(40)} Task DoD`)
    for (const item of packet.taskDod) {
      lines.push(`- [ ] ${item}`)
    }
    lines.push("")
  }

  lines.push(`${"─".repeat(40)} After Completion`)
  for (const item of packet.afterCompletion) {
    lines.push(item)
  }

  return lines.join("\n")
}

export function buildContext(agentId: AgentId, state: ProjectState): string {
  return renderAgentTaskPacket(buildAgentTaskPacket(agentId, state))
}

import type { AgentId, AgentTaskPacket, Milestone, ProjectState, Task } from "../../types"
import {
  getAgentEntry,
  getUnsupportedPhaseGuidance,
  needsFrontendDesigner,
} from "./agent-registry"
import { buildAgentTaskPacket, renderAgentTaskPacket } from "./context-builder"
import { getPhaseReadiness } from "./phase-readiness"

export interface DispatchResult {
  type: "agent" | "manual" | "none"
  agentId?: AgentId
  context?: string
  message: string
  packet?: AgentTaskPacket
  postAction?: string
}

function getCurrentMilestone(state: ProjectState): Milestone | undefined {
  return state.execution.milestones.find(m => m.id === state.execution.currentMilestone)
}

function getCurrentTask(state: ProjectState): Task | undefined {
  return state.execution.milestones
    .flatMap(m => m.tasks)
    .find(t => t.id === state.execution.currentTask)
}

function needsBacklogSync(state: ProjectState): boolean {
  return state.docs.prd.milestoneCount > state.execution.milestones.length
}

function agentDispatch(
  agentId: AgentId,
  state: ProjectState,
  postAction?: string,
): DispatchResult {
  const entry = getAgentEntry(agentId)
  if (!entry) {
    return { type: "none", message: `Agent "${agentId}" not found in registry.` }
  }
  const packet = buildAgentTaskPacket(agentId, state)
  const context = renderAgentTaskPacket(packet)
  return {
    type: "agent",
    agentId,
    context,
    message: entry.name,
    packet,
    postAction,
  }
}

function manualGuidance(message: string): DispatchResult {
  return { type: "manual", message }
}

function noAction(message: string): DispatchResult {
  return { type: "none", message }
}

function phaseAdvanceGuidance(lines: string[]): DispatchResult {
  return manualGuidance(lines.join("\n"))
}

function getDiscoveryAction(state: ProjectState): DispatchResult {
  const readiness = getPhaseReadiness(state)
  if (readiness.ready) {
    return phaseAdvanceGuidance([
      "Discovery outputs are ready.",
      "Run:",
      "  bun harness:advance",
      "  bun .harness/orchestrator.ts",
    ])
  }

  return agentDispatch(
    "project-discovery",
    state,
    [
      "After completing Q0-Q9:",
      "1. bun harness:advance",
      "2. bun .harness/orchestrator.ts",
    ].join("\n"),
  )
}

function getExecutingAction(state: ProjectState): DispatchResult {
  const milestone = getCurrentMilestone(state)
  if (!milestone) {
    if (needsBacklogSync(state)) {
      return manualGuidance(
        "PRD contains unsynced milestone scope. Run:\n" +
        "  bun harness:sync-backlog\n" +
        "  bun .harness/orchestrator.ts"
      )
    }
    const reviewMilestone = state.execution.milestones.find(m => m.status === "REVIEW")
    if (reviewMilestone) {
      return manualGuidance(
        `Milestone ${reviewMilestone.id} is in REVIEW.\n` +
        `From the main worktree, run bun harness:autoflow to auto-compact, merge, and continue.\n` +
        `Manual fallback: bun harness:merge-milestone ${reviewMilestone.id}`
      )
    }
    return noAction("No active milestone. Run: bun .harness/init.ts --from-prd")
  }

  if (milestone.status === "REVIEW") {
    return manualGuidance(
      `Milestone ${milestone.id} is in REVIEW.\n` +
      `From the main worktree, run bun harness:autoflow to auto-compact, merge, and continue.\n` +
      `Manual fallback: bun harness:merge-milestone ${milestone.id}`
    )
  }

  if (needsFrontendDesigner(state)) {
    return agentDispatch("frontend-designer", state)
  }

  const task = getCurrentTask(state)
  if (!task) return noAction("No active task in current milestone.")

  if (task.retryCount >= 3) {
    return manualGuidance(
      `Task ${task.id} has failed ${task.retryCount} times. Manual intervention required. Reference: agents/orchestrator.md:88`,
    )
  }

  if (task.isUI) {
    return agentDispatch(
      "execution-engine",
      state,
      "UI Task: After implementation + self-validation passes, run Design Review (agents/design-reviewer.md)",
    )
  }

  return agentDispatch(
    "execution-engine",
    state,
    "Non-UI Task: After implementation + self-validation passes, run Code Review via bun .harness/orchestrator.ts --code-review",
  )
}

function getPrdArchAction(state: ProjectState): DispatchResult {
  const readiness = getPhaseReadiness(state)
  if (readiness.ready) {
    return phaseAdvanceGuidance([
      "PRD / Architecture outputs are ready.",
      "Run:",
      "  bun harness:advance",
      "  bun .harness/orchestrator.ts",
    ])
  }

  return agentDispatch(
    "prd-architect",
    state,
    [
      "After completing PRD / Architecture / GitBook skeleton:",
      "1. If UI project: dispatch Frontend Designer for DESIGN_SYSTEM.md + product-prototype.html",
      "2. bun harness:advance",
      "3. bun .harness/orchestrator.ts",
    ].join("\n"),
  )
}

function getScaffoldAction(state: ProjectState): DispatchResult {
  const readiness = getPhaseReadiness(state)
  if (readiness.ready) {
    return phaseAdvanceGuidance([
      "Scaffold outputs are ready.",
      "Run:",
      "  bun install",
      "  bun harness:advance",
      "  bun .harness/orchestrator.ts",
    ])
  }

  return agentDispatch(
    "scaffold-generator",
    state,
    [
      "After completing Scaffold:",
      "1. bun install",
      "2. bun harness:advance",
      "3. bun .harness/orchestrator.ts",
    ].join("\n"),
  )
}

function getCompleteAction(state: ProjectState): DispatchResult {
  if (needsBacklogSync(state)) {
    return manualGuidance(
      "New PRD milestone scope was detected after completion. Run:\n" +
      "  bun harness:sync-backlog\n" +
      "  bun .harness/orchestrator.ts"
    )
  }

  return agentDispatch(
    "context-compactor",
    state,
    [
      "Project is complete:",
      "1. bun harness:advance",
      "2. bun harness:compact --status",
    ].join("\n"),
  )
}

export function dispatch(state: ProjectState): DispatchResult {
  const guidance = getUnsupportedPhaseGuidance(state.phase)
  if (guidance) return manualGuidance(guidance)

  switch (state.phase) {
    case "DISCOVERY":
      return getDiscoveryAction(state)
    case "MARKET_RESEARCH":
      return getPhaseReadiness(state).ready
        ? phaseAdvanceGuidance([
            "Market Research outputs are ready.",
            "Run:",
            "  bun harness:advance",
            "  bun .harness/orchestrator.ts",
          ])
        : agentDispatch("market-research", state)
    case "TECH_STACK":
      return getPhaseReadiness(state).ready
        ? phaseAdvanceGuidance([
            "Tech Stack outputs are ready.",
            "Run:",
            "  bun harness:advance",
            "  bun .harness/orchestrator.ts",
          ])
        : agentDispatch("tech-stack-advisor", state)
    case "PRD_ARCH":
      return getPrdArchAction(state)
    case "SCAFFOLD":
      return getScaffoldAction(state)
    case "EXECUTING":
      return getExecutingAction(state)
    case "VALIDATING":
      return agentDispatch("harness-validator", state)
    case "COMPLETE":
      return getCompleteAction(state)
    default:
      return noAction(`Unhandled phase: ${state.phase}`)
  }
}

export function getStatus(state: ProjectState): string {
  const milestone = getCurrentMilestone(state)
  const task = getCurrentTask(state)
  const result = dispatch(state)
  const readiness = getPhaseReadiness(state)

  const lines: string[] = []
  lines.push(`${"═".repeat(50)}`)
  lines.push("  Harness Orchestrator — Status")
  lines.push(`${"═".repeat(50)}`)
  lines.push("")
  lines.push(`Phase:     ${state.phase}`)
  lines.push(`Milestone: ${milestone ? `${milestone.id} — ${milestone.name} (${milestone.status})` : "—"}`)
  lines.push(`Task:      ${task ? `${task.id} — ${task.name} (${task.status})` : "—"}`)
  lines.push(`Worktree:  ${state.execution.currentWorktree || "—"}`)
  lines.push(`Phase Ready: ${readiness.ready ? "yes" : "no"}`)
  lines.push("")

  const totalTasks = state.execution.milestones.flatMap(m => m.tasks).length
  const doneTasks = state.execution.milestones.flatMap(m => m.tasks).filter(t => t.status === "DONE").length
  const pct = totalTasks ? Math.round((doneTasks / totalTasks) * 100) : 0
  const bar = "█".repeat(Math.round(pct / 5)) + "░".repeat(20 - Math.round(pct / 5))
  lines.push(`Progress:  [${bar}] ${pct}% (${doneTasks}/${totalTasks})`)
  lines.push("")

  lines.push(`${"─".repeat(40)} Next Action`)
  if (result.type === "agent") {
    lines.push(`Agent: ${result.message}`)
  } else if (result.type === "manual") {
    lines.push(`Manual: ${result.message}`)
  } else {
    lines.push(`None: ${result.message}`)
  }

  if (readiness.missingOutputs.length > 0) {
    lines.push("")
    lines.push(`${"─".repeat(40)} Missing Outputs`)
    for (const item of readiness.missingOutputs) {
      lines.push(`- ${item}`)
    }
  }

  return lines.join("\n")
}

export function dispatchCodeReview(state: ProjectState): DispatchResult {
  if (state.phase !== "EXECUTING") {
    return noAction("Code Review is only available during EXECUTING phase.")
  }
  const task = getCurrentTask(state)
  if (!task) {
    return noAction("No active task. Cannot run Code Review.")
  }
  if (task.isUI) {
    return noAction(`Task ${task.id} is a UI task. Code Review only applies to non-UI tasks.`)
  }
  if (task.status !== "IN_PROGRESS") {
    return noAction(`Task ${task.id} is ${task.status}. Code Review requires an IN_PROGRESS task.`)
  }
  if (task.retryCount >= 3) {
    return noAction(
      `Task ${task.id} has failed ${task.retryCount} times. Manual intervention required.`,
    )
  }
  return agentDispatch("code-reviewer", state)
}

export function dispatchDesignReview(state: ProjectState): DispatchResult {
  if (state.phase !== "EXECUTING") {
    return noAction("Design Review is only available during EXECUTING phase.")
  }
  const task = getCurrentTask(state)
  if (!task) {
    return noAction("No active task. Cannot run Design Review.")
  }
  if (!task.isUI) {
    return noAction(`Task ${task.id} is not a UI task. Design Review only applies to UI tasks.`)
  }
  if (task.status !== "IN_PROGRESS") {
    return noAction(`Task ${task.id} is ${task.status}. Design Review requires an IN_PROGRESS task.`)
  }
  if (task.retryCount >= 3) {
    return noAction(
      `Task ${task.id} has failed ${task.retryCount} times. Manual intervention required.`,
    )
  }
  return agentDispatch("design-reviewer", state)
}

import { existsSync } from "fs"
import type { AgentId, AgentMaterialPolicy, ProjectState, Task } from "../../types"
import { getAgentEntry } from "./agent-registry"

const CONTEXT_SNAPSHOT_PATH = "docs/progress/CONTEXT_SNAPSHOT.md"
const DESIGN_SYSTEM_PATH = "docs/design/DESIGN_SYSTEM.md"

function existingRefs(paths: Array<string | undefined>): string[] {
  const refs: string[] = []
  for (const path of paths) {
    if (!path) continue
    if (!existsSync(path)) continue
    refs.push(path)
  }
  return refs
}

function existingRef(path: string): string | undefined {
  return existsSync(path) ? path : undefined
}

function getCurrentTask(state: ProjectState): Task | undefined {
  return state.execution.milestones
    .flatMap(milestone => milestone.tasks)
    .find(task => task.id === state.execution.currentTask)
}

function currentMilestoneSpecPath(state: ProjectState): string | undefined {
  const milestoneId = state.execution.currentMilestone?.toLowerCase()
  if (!milestoneId) return undefined
  return existingRef(`docs/design/${milestoneId}-ui-spec.md`)
}

function prdRef(kind: "index" | "requirements" | "design"): string | undefined {
  switch (kind) {
    case "index":
      return existingRef("docs/PRD.md") ?? existingRef("docs/prd/01-overview.md")
    case "requirements":
      return existingRef("docs/prd/03-requirements.md") ?? existingRef("docs/PRD.md")
    case "design":
      return (
        existingRef("docs/prd/02-users-and-design.md") ??
        existingRef("docs/prd/03-requirements.md") ??
        existingRef("docs/PRD.md")
      )
  }
}

function architectureRef(kind: "index" | "frontend" | "rules"): string | undefined {
  switch (kind) {
    case "index":
      return existingRef("docs/ARCHITECTURE.md") ?? existingRef("docs/architecture/01-system-overview.md")
    case "frontend":
      return (
        existingRef("docs/architecture/01-system-overview.md") ??
        existingRef("docs/architecture/02-project-structure.md") ??
        existingRef("docs/ARCHITECTURE.md")
      )
    case "rules":
      return (
        existingRef("docs/architecture/03-dependency-rules.md") ??
        existingRef("docs/architecture/04-state-and-validation.md") ??
        existingRef("docs/ARCHITECTURE.md")
      )
  }
}

function commonConstraints(): string[] {
  return [
    "Keep AGENTS.md and CLAUDE.md synchronized [G8].",
    "Do not introduce forbidden patterns or secret-like values in source code [G4].",
    "Use explicit validation gates before progression; do not hand-wave completion.",
  ]
}

function executionConstraints(task?: Task): string[] {
  const constraints = [
    "Implement only work that maps to the current task and PRD reference [G1].",
    "If the user asks for new scope outside the current task / PRD reference, stop implementation, update PRD first, then run bun harness:sync-backlog before coding.",
    "Do not land feature work directly on main/master [G2].",
    "Create exactly one Atomic Commit per task with Task-ID and PRD mapping [G10].",
    "After task completion, synchronize .harness/state.json and docs/PROGRESS.md.",
  ]

  if (task?.isUI) {
    constraints.push("UI work requires a design spec before implementation and Design Review approval before commit [G7].")
  }

  return constraints
}

function progressRefs(): string[] {
  return existingRefs(["docs/PROGRESS.md", CONTEXT_SNAPSHOT_PATH])
}

function packetRefsFor(agentId: AgentId, state: ProjectState): { optionalRefs: string[]; requiredRefs: string[] } {
  const entry = getAgentEntry(agentId)
  const task = getCurrentTask(state)
  const base = [entry?.specPath, ".harness/state.json"]

  switch (agentId) {
    case "project-discovery":
      return {
        requiredRefs: existingRefs(base),
        optionalRefs: existingRefs(["README.md", ...progressRefs()]),
      }

    case "market-research":
      return {
        requiredRefs: existingRefs(base),
        optionalRefs: existingRefs([prdRef("index"), "README.md"]),
      }

    case "tech-stack-advisor":
      return {
        requiredRefs: existingRefs(base),
        optionalRefs: existingRefs([prdRef("index"), architectureRef("index")]),
      }

    case "prd-architect":
      return {
        requiredRefs: existingRefs(base),
        optionalRefs: existingRefs([prdRef("index"), architectureRef("index")]),
      }

    case "scaffold-generator":
      return {
        requiredRefs: existingRefs([
          ...base,
          prdRef("requirements"),
          architectureRef("rules"),
        ]),
        optionalRefs: existingRefs(progressRefs()),
      }

    case "frontend-designer":
      return {
        requiredRefs: existingRefs([
          ...base,
          prdRef("design"),
          prdRef("requirements"),
          architectureRef("frontend"),
        ]),
        optionalRefs: existingRefs([DESIGN_SYSTEM_PATH, currentMilestoneSpecPath(state), ...progressRefs()]),
      }

    case "execution-engine": {
      const requiredRefs = [...base]
      if (entry?.subSpecs) {
        requiredRefs.push(
          ...(task?.type === "SPIKE"
            ? ["agents/execution-engine/03-spike-workflow.md"]
            : ["agents/execution-engine/01-preflight.md", "agents/execution-engine/02-task-loop.md"]),
        )
      }

      return {
        requiredRefs: existingRefs([
          ...requiredRefs,
          prdRef("requirements"),
          architectureRef("rules"),
        ]),
        optionalRefs: existingRefs([
          ...progressRefs(),
          task?.isUI ? DESIGN_SYSTEM_PATH : undefined,
          task?.isUI ? currentMilestoneSpecPath(state) : undefined,
        ]),
      }
    }

    case "design-reviewer":
      return {
        requiredRefs: existingRefs([
          ...base,
          DESIGN_SYSTEM_PATH,
          currentMilestoneSpecPath(state),
        ]),
        optionalRefs: existingRefs(progressRefs()),
      }

    case "harness-validator":
      return {
        requiredRefs: existingRefs([...base, "docs/PROGRESS.md"]),
        optionalRefs: existingRefs([CONTEXT_SNAPSHOT_PATH]),
      }

    case "context-compactor":
      return {
        requiredRefs: existingRefs([...base, "docs/PROGRESS.md"]),
        optionalRefs: existingRefs([CONTEXT_SNAPSHOT_PATH]),
      }

    case "code-reviewer":
      return {
        requiredRefs: existingRefs([
          ...base,
          prdRef("requirements"),
          architectureRef("rules"),
        ]),
        optionalRefs: existingRefs(progressRefs()),
      }
  }
}

export function getAgentMaterialPolicy(agentId: AgentId, state: ProjectState): AgentMaterialPolicy {
  const task = getCurrentTask(state)
  const { optionalRefs, requiredRefs } = packetRefsFor(agentId, state)

  switch (agentId) {
    case "execution-engine":
      return {
        agentId,
        conditions: task?.isUI ? ["Attach design materials only for UI tasks."] : undefined,
        inlineConstraints: [...commonConstraints(), ...executionConstraints(task)],
        optionalRefs,
        requiredRefs,
      }

    case "design-reviewer":
      return {
        agentId,
        conditions: ["Only valid for IN_PROGRESS UI tasks."],
        inlineConstraints: [
          ...commonConstraints(),
          "Review against the current milestone UI spec only; do not fan out into unrelated docs.",
          "Block commit if Design Review approval is missing for a UI task [G7].",
        ],
        optionalRefs,
        requiredRefs,
      }

    case "frontend-designer":
      return {
        agentId,
        conditions: ["Attach design materials only for the active UI milestone."],
        inlineConstraints: [
          ...commonConstraints(),
          "Define or update the design system only for the active product surface.",
          "Design output must cover loading, empty, error, responsive, and accessibility states.",
        ],
        optionalRefs,
        requiredRefs,
      }

    case "harness-validator":
      return {
        agentId,
        inlineConstraints: [
          ...commonConstraints(),
          "Validate against runtime gates and current state, not against broad documentation scans.",
        ],
        optionalRefs,
        requiredRefs,
      }

    case "context-compactor":
      return {
        agentId,
        inlineConstraints: [
          ...commonConstraints(),
          "Use docs/PROGRESS.md and CONTEXT_SNAPSHOT for recovery guidance; do not scan docs/progress/ by default.",
        ],
        optionalRefs,
        requiredRefs,
      }

    case "scaffold-generator":
      return {
        agentId,
        inlineConstraints: [
          ...commonConstraints(),
          "Do not bootstrap product frameworks during scaffold setup; stay at the Harness baseline.",
        ],
        optionalRefs,
        requiredRefs,
      }

    case "code-reviewer":
      return {
        agentId,
        conditions: ["Only valid for non-UI IN_PROGRESS tasks."],
        inlineConstraints: [
          ...commonConstraints(),
          "Review security practices: no hardcoded secrets, proper input validation, safe dependency usage.",
          "Review performance: avoid unnecessary re-renders, O(n²) loops, unbounded queries, and memory leaks.",
          "Review architecture: verify dependency direction, layer separation, and adherence to project conventions.",
        ],
        optionalRefs,
        requiredRefs,
      }

    default:
      return {
        agentId,
        inlineConstraints: commonConstraints(),
        optionalRefs,
        requiredRefs,
      }
  }
}

import { afterEach, beforeEach, expect, test } from "bun:test"
import { mkdtempSync, mkdirSync, rmSync, writeFileSync } from "fs"
import { tmpdir } from "os"
import { join } from "path"
import type { ProjectState } from "../../types"
import { initState } from "../state-core"
import { writeProjectStateToDisk } from "../state-io"
import { deriveStateFromFilesystem } from "../shared"
import { runAutoflow } from "./autoflow"
import { dispatch } from "./dispatcher"
import { getPhaseReadiness } from "./phase-readiness"

let originalCwd = ""
let workspaceDir = ""

function createState(phase: ProjectState["phase"]): ProjectState {
  const state = initState({})
  state.phase = phase
  state.projectInfo.name = "phase-ready-project"
  state.projectInfo.displayName = "Phase Ready Project"
  state.projectInfo.concept = "A fixture project for orchestrator readiness tests."
  state.projectInfo.problem = "Phase work can be skipped when outputs are missing."
  state.projectInfo.goal = "Keep autoflow and dispatch aligned with actual phase artifacts."
  state.projectInfo.types = ["monorepo", "web-app"]
  state.projectInfo.aiProvider = "none"
  state.projectInfo.teamSize = "solo"
  state.projectInfo.isGreenfield = true
  state.docs.prd.exists = true
  state.docs.prd.milestoneCount = 1
  state.docs.architecture.exists = true
  state.docs.gitbook.initialized = true
  state.docs.gitbook.summaryExists = true
  return state
}

function write(path: string, content = ""): void {
  const fullPath = join(workspaceDir, path)
  mkdirSync(join(fullPath, ".."), { recursive: true })
  writeFileSync(fullPath, content)
}

function materializeScaffoldArtifacts(state: ProjectState): void {
  write("AGENTS.md", "# AGENTS\n")
  write("CLAUDE.md", "# AGENTS\n")
  write(".env.example", "EXAMPLE=1\n")
  write(".env.local", "LOCAL=1\n")
  write("biome.json", "{}\n")
  write(".github/workflows/ci.yml", "name: ci\n")
  write("docs/PROGRESS.md", "# Progress\n")
  write("packages/shared/package.json", "{\n  \"name\": \"shared\"\n}\n")
  write("apps/web/package.json", "{\n  \"name\": \"web\"\n}\n")
  write("scripts/harness-local/restore.ts", "export {}\n")
  write("scripts/harness-local/manifest.json", "{}\n")

  for (const file of [
    "advance.ts",
    "compact.ts",
    "add-surface.ts",
    "audit.ts",
    "sync-docs.ts",
    "sync-skills.ts",
    "api-add.ts",
    "merge-milestone.ts",
  ]) {
    write(`.harness/${file}`, "export {}\n")
  }

  write(
    "package.json",
    JSON.stringify(
      {
        name: "phase-ready-project",
        private: true,
        workspaces: ["apps/*", "packages/*"],
        scripts: {
          "harness:advance": "bun .harness/advance.ts",
          "harness:sync-backlog": "bun .harness/init.ts --sync-from-prd",
          "harness:autoflow": "bun .harness/orchestrator.ts --auto",
          "harness:merge-milestone": "bun .harness/merge-milestone.ts",
        },
      },
      null,
      2,
    ) + "\n",
  )

  writeProjectStateToDisk(state, join(workspaceDir, ".harness/state.json"))
}

beforeEach(() => {
  originalCwd = process.cwd()
  workspaceDir = mkdtempSync(join(tmpdir(), "harness-phase-readiness-"))
  process.chdir(workspaceDir)
})

afterEach(() => {
  process.chdir(originalCwd)
  rmSync(workspaceDir, { force: true, recursive: true })
})

test("scaffold readiness reports missing scaffold outputs", () => {
  const state = createState("SCAFFOLD")
  writeProjectStateToDisk(state, ".harness/state.json")

  const readiness = getPhaseReadiness(state)

  expect(readiness.ready).toBe(false)
  expect(readiness.missingOutputs).toContain("AGENTS.md is present")
  expect(readiness.missingOutputs).toContain(".harness/advance.ts is present")
})

test("dispatch sends scaffold-generator when scaffold outputs are missing", () => {
  const state = createState("SCAFFOLD")
  writeProjectStateToDisk(state, ".harness/state.json")

  const result = dispatch(state)

  expect(result.type).toBe("agent")
  expect(result.agentId).toBe("scaffold-generator")
  expect(result.packet?.missingOutputs).toContain("AGENTS.md is present")
})

test("dispatch switches to manual advance guidance once scaffold outputs are ready", () => {
  const state = createState("SCAFFOLD")
  materializeScaffoldArtifacts(state)
  const syncedState = deriveStateFromFilesystem(state)

  const result = dispatch(syncedState)

  expect(result.type).toBe("manual")
  expect(result.message).toContain("Scaffold outputs are ready.")
  expect(result.message).toContain("bun harness:advance")
})

test("autoflow stops at scaffold when artifacts are missing instead of running commands", async () => {
  const state = createState("SCAFFOLD")
  writeProjectStateToDisk(state, ".harness/state.json")

  const exitCode = await runAutoflow()

  expect(exitCode).toBe(0)
})

import { existsSync, readFileSync } from "fs"
import type { Phase, ProjectState } from "../../types"
import {
  ARCHITECTURE_DIR,
  ARCHITECTURE_PATH,
  documentExists,
  PROGRESS_DIR,
  PROGRESS_PATH,
  PRD_DIR,
  PRD_PATH,
  STATE_PATH,
} from "../shared"
import { hasAgentSurface, surfaceWorkspaceList } from "../surfaces"

type OutputCheck = {
  label: string
  ok: boolean
}

export interface PhaseReadiness {
  missingOutputs: string[]
  phase: Phase
  ready: boolean
  requiredOutputs: string[]
}

function check(label: string, ok: boolean): OutputCheck {
  return { label, ok }
}

function buildReadiness(phase: Phase, checks: OutputCheck[]): PhaseReadiness {
  return {
    missingOutputs: checks.filter(item => !item.ok).map(item => item.label),
    phase,
    ready: checks.every(item => item.ok),
    requiredOutputs: checks.map(item => item.label),
  }
}

function packageJsonHasScript(scriptName: string): boolean {
  if (!existsSync("package.json")) return false

  try {
    const pkg = JSON.parse(readFileSync("package.json", "utf-8")) as {
      scripts?: Record<string, string>
    }
    return Boolean(pkg.scripts?.[scriptName])
  } catch {
    return false
  }
}

function packageJsonHasWorkspace(workspace: string): boolean {
  if (!existsSync("package.json")) return false

  try {
    const pkg = JSON.parse(readFileSync("package.json", "utf-8")) as {
      workspaces?: string[]
    }
    return Boolean(pkg.workspaces?.includes(workspace))
  } catch {
    return false
  }
}

function discoveryChecks(state: ProjectState): OutputCheck[] {
  return [
    check("projectInfo.name is set [Q1]", !!state.projectInfo.name),
    check("projectInfo.displayName is set", !!state.projectInfo.displayName),
    check("projectInfo.concept is set [Q2]", !!state.projectInfo.concept),
    check("projectInfo.problem is set [Q3]", !!state.projectInfo.problem),
    check("projectInfo.goal is set [Q4]", !!state.projectInfo.goal),
    check("projectInfo.types is selected [Q5]", state.projectInfo.types.length > 0),
    check("aiProvider is selected [Q6]", !!state.projectInfo.aiProvider),
    check("teamSize is selected [Q8]", !!state.projectInfo.teamSize),
  ]
}

function marketResearchChecks(state: ProjectState): OutputCheck[] {
  return [
    check("marketResearch.summary is present", !!state.marketResearch.summary),
    check("marketResearch.competitors has at least one entry", state.marketResearch.competitors.length > 0),
  ]
}

function techStackChecks(state: ProjectState): OutputCheck[] {
  return [
    check("techStack.confirmed = true", state.techStack.confirmed),
    check("techStack.decisions has at least one entry", state.techStack.decisions.length > 0),
    check(
      "every techStack decision has an adrFile",
      state.techStack.decisions.every(decision => !!decision.adrFile?.trim()),
    ),
  ]
}

function prdArchChecks(state: ProjectState): OutputCheck[] {
  return [
    check("docs/PRD.md or docs/prd/ is present", documentExists(PRD_PATH, PRD_DIR)),
    check(
      "docs/ARCHITECTURE.md or docs/architecture/ is present",
      documentExists(ARCHITECTURE_PATH, ARCHITECTURE_DIR),
    ),
    check("docs/gitbook/SUMMARY.md is present", existsSync("docs/gitbook/SUMMARY.md")),
    check("the PRD includes at least 1 milestone", state.docs.prd.milestoneCount > 0),
  ]
}

function scaffoldChecks(state: ProjectState): OutputCheck[] {
  const checks: OutputCheck[] = [
    check("AGENTS.md is present", state.scaffold.agentsMdExists),
    check("CLAUDE.md is present", state.scaffold.claudeMdExists),
    check(".harness/state.json is present", existsSync(STATE_PATH)),
    check("docs/PROGRESS.md or docs/progress/ is present", documentExists(PROGRESS_PATH, PROGRESS_DIR)),
    check(".env.example is present", state.scaffold.envExampleExists),
    check(".env.local skeleton is present", existsSync(".env.local")),
    check("biome.json is present", existsSync("biome.json")),
    check(".harness/advance.ts is present", existsSync(".harness/advance.ts")),
    check(".harness/compact.ts is present", existsSync(".harness/compact.ts")),
    check(".harness/add-surface.ts is present", existsSync(".harness/add-surface.ts")),
    check(".harness/audit.ts is present", existsSync(".harness/audit.ts")),
    check(".harness/sync-docs.ts is present", existsSync(".harness/sync-docs.ts")),
    check(".harness/sync-skills.ts is present", existsSync(".harness/sync-skills.ts")),
    check(".harness/api-add.ts is present", existsSync(".harness/api-add.ts")),
    check(".harness/merge-milestone.ts is present", existsSync(".harness/merge-milestone.ts")),
    check("scripts/harness-local/restore.ts is present", existsSync("scripts/harness-local/restore.ts")),
    check("scripts/harness-local/manifest.json is present", existsSync("scripts/harness-local/manifest.json")),
    check("package.json includes harness:advance", packageJsonHasScript("harness:advance")),
    check("package.json includes harness:sync-backlog", packageJsonHasScript("harness:sync-backlog")),
    check("package.json includes harness:autoflow", packageJsonHasScript("harness:autoflow")),
    check(
      "package.json includes harness:merge-milestone",
      packageJsonHasScript("harness:merge-milestone"),
    ),
    check("package.json includes apps/* workspace", packageJsonHasWorkspace("apps/*")),
    check("package.json includes packages/* workspace", packageJsonHasWorkspace("packages/*")),
    check("packages/shared/package.json is present", existsSync("packages/shared/package.json")),
    check("CI workflow is present", state.scaffold.ciExists),
  ]

  for (const workspace of surfaceWorkspaceList(state.projectInfo.types)) {
    checks.push(check(`apps/${workspace}/package.json is present`, existsSync(`apps/${workspace}/package.json`)))
  }

  if (hasAgentSurface(state.projectInfo.types)) {
    checks.push(check("SKILLS.md is present", existsSync("SKILLS.md")))
    checks.push(check("skills/api-wrapper/SKILL.md is present", existsSync("skills/api-wrapper/SKILL.md")))
    checks.push(check("packages/shared/api/README.md is present", existsSync("packages/shared/api/README.md")))
  }

  return checks
}

export function getPhaseReadiness(state: ProjectState): PhaseReadiness {
  switch (state.phase) {
    case "DISCOVERY":
      return buildReadiness(state.phase, discoveryChecks(state))
    case "MARKET_RESEARCH":
      return buildReadiness(state.phase, marketResearchChecks(state))
    case "TECH_STACK":
      return buildReadiness(state.phase, techStackChecks(state))
    case "PRD_ARCH":
      return buildReadiness(state.phase, prdArchChecks(state))
    case "SCAFFOLD":
      return buildReadiness(state.phase, scaffoldChecks(state))
    case "EXECUTING":
      return buildReadiness(state.phase, [
        check("execution backlog has at least 1 milestone", state.execution.milestones.length > 0),
        check(
          "there is an active milestone or a milestone in REVIEW",
          Boolean(state.execution.currentMilestone) || state.execution.milestones.some(item => item.status === "REVIEW"),
        ),
      ])
    case "VALIDATING":
      return buildReadiness(state.phase, [
        check("all milestones are complete", state.execution.allMilestonesComplete),
      ])
    case "COMPLETE":
      return buildReadiness(state.phase, [])
  }
}

import { mkdirSync, writeFileSync } from "fs"
import { join } from "path"
import type { Milestone, ProjectState, Task } from "../types"
import { PROGRESS_DIR, PROGRESS_PATH } from "./shared"

function statusIcon(status: Task["status"]): string {
  switch (status) {
    case "DONE":
      return "[x]"
    case "SKIPPED":
      return "[-]"
    case "BLOCKED":
      return "[!]"
    case "IN_PROGRESS":
      return "[~]"
    default:
      return "[ ]"
  }
}

function formatTimestamp(value?: string): string | undefined {
  if (!value) return undefined
  return value.replace("T", " ").replace(/\.\d{3}Z$/, "Z")
}

function taskLifecycleSuffix(task: Task): string {
  const details: string[] = []

  if (task.commitHash) {
    details.push(`commit \`${task.commitHash.slice(0, 7)}\``)
  }
  if (task.status === "IN_PROGRESS" && task.startedAt) {
    details.push(`started ${formatTimestamp(task.startedAt)}`)
  }
  if (task.status === "BLOCKED") {
    details.push(`blocked ${formatTimestamp(task.blockedAt) ?? "time not recorded"}`)
    if (task.blockedReason) {
      details.push(`reason: ${task.blockedReason}`)
    }
  }
  if (task.status === "DONE" && task.completedAt) {
    details.push(`completed ${formatTimestamp(task.completedAt)}`)
  }

  return details.length > 0 ? ` — ${details.join(" — ")}` : ""
}

function taskLabel(task: Task, currentTaskId: string): string {
  const suffix = task.id === currentTaskId ? " — <- Current Task" : ""
  return `${statusIcon(task.status)} ${task.id}: ${task.name}${taskLifecycleSuffix(task)}${suffix}`
}

function milestoneHeading(milestone: Milestone): string {
  const icon =
    milestone.status === "COMPLETE" || milestone.status === "MERGED"
      ? "✅ Complete"
      : milestone.status === "IN_PROGRESS"
        ? "🔄 In Progress"
        : milestone.status === "REVIEW"
          ? "🟡 Awaiting Review"
          : "⏳ Not Started"
  return `### ${milestone.id}: ${milestone.name} ${icon}`
}

function progressBar(done: number, total: number): string {
  const ratio = total === 0 ? 0 : done / total
  const filled = Math.min(10, Math.round(ratio * 10))
  return `${"█".repeat(filled)}${"░".repeat(10 - filled)}`
}

function findCurrentTask(state: ProjectState): Task | undefined {
  const explicitTask = state.execution.milestones
    .flatMap(milestone => milestone.tasks)
    .find(task => task.id === state.execution.currentTask)
  if (explicitTask) return explicitTask

  return state.execution.milestones
    .flatMap(milestone => milestone.tasks)
    .find(task => task.status === "IN_PROGRESS")
    ?? state.execution.milestones.flatMap(milestone => milestone.tasks).find(task => task.status === "PENDING")
}

function findCurrentMilestone(state: ProjectState, currentTask?: Task): Milestone | undefined {
  const explicitMilestone = state.execution.milestones.find(milestone => milestone.id === state.execution.currentMilestone)
  if (explicitMilestone) return explicitMilestone

  if (currentTask) {
    const taskMilestone = state.execution.milestones.find(milestone => milestone.tasks.some(task => task.id === currentTask.id))
    if (taskMilestone) return taskMilestone
  }

  return state.execution.milestones.find(milestone => milestone.status === "IN_PROGRESS")
    ?? state.execution.milestones.find(milestone => milestone.status === "REVIEW")
    ?? state.execution.milestones.find(milestone => milestone.status === "PENDING")
}

function nextWorktreePath(state: ProjectState, currentMilestone?: Milestone): string {
  if (state.execution.currentWorktree) return state.execution.currentWorktree
  if (currentMilestone?.worktreePath) return currentMilestone.worktreePath
  if (state.projectInfo.name) return `../${state.projectInfo.name}-m1`
  return "../project-m1"
}

function buildTaskActivityLog(state: ProjectState): string[] {
  const activity = state.execution.milestones.flatMap(milestone =>
    milestone.tasks.flatMap(task => {
      const entries: Array<{ at: string; text: string }> = []
      if (task.startedAt) {
        entries.push({
          at: task.startedAt,
          text: `${task.startedAt}: ${task.id} entered IN_PROGRESS in ${milestone.id} — ${task.name}`,
        })
      }
      if (task.blockedAt) {
        entries.push({
          at: task.blockedAt,
          text: `${task.blockedAt}: ${task.id} became BLOCKED — ${task.blockedReason ?? "reason not recorded"}`,
        })
      }
      if (task.completedAt) {
        entries.push({
          at: task.completedAt,
          text: `${task.completedAt}: ${task.id} completed${task.commitHash ? ` (${task.commitHash.slice(0, 7)})` : ""}`,
        })
      }
      return entries
    }),
  )

  return activity
    .sort((left, right) => right.at.localeCompare(left.at))
    .map(entry => `- ${entry.text.replace("T", " ").replace(/\.\d{3}Z$/, "Z")}`)
}

function buildProgressSnapshot(state: ProjectState) {
  const tasks = state.execution.milestones.flatMap(milestone => milestone.tasks)
  const doneTasks = tasks.filter(task => task.status === "DONE").length
  const totalTasks = tasks.length
  const percent = totalTasks === 0 ? 0 : Math.round((doneTasks / totalTasks) * 100)
  const currentTask = findCurrentTask(state)
  const currentMilestone = findCurrentMilestone(state, currentTask) ?? state.execution.milestones[0]
  const blockedTasks = tasks.filter(task => task.status === "BLOCKED")
  const activityLog = buildTaskActivityLog(state)

  const backlog =
    state.execution.milestones.length === 0
      ? [
          "### Task Backlog not yet initialized",
          "- [ ] Run `bun harness:advance` to advance from the current phase to the execution backlog",
        ].join("\n")
      : state.execution.milestones
          .map(milestone =>
            [
              milestoneHeading(milestone),
              ...milestone.tasks.map(task => `- ${taskLabel(task, state.execution.currentTask)}`),
            ].join("\n"),
          )
          .join("\n\n")

  const blockedTable =
    blockedTasks.length === 0
      ? "| — | — | — | — |\n"
      : `${blockedTasks
          .map(
            task =>
              `| ${task.id} | ${task.blockedReason ?? "Not recorded"} | Requires user or external dependency | ${formatTimestamp(task.blockedAt) ?? formatTimestamp(state.updatedAt)} |`,
          )
          .join("\n")}\n`

  const worktreeLines =
    state.execution.milestones.length === 0
      ? `./                main / current\n${nextWorktreePath(state)}    milestone/m1-foundation`
      : state.execution.milestones
          .map(milestone => `${milestone.worktreePath}    ${milestone.branch}`)
          .join("\n")

  const currentTaskLabel = currentTask
    ? `${currentTask.id} — ${currentTask.name} (${currentTask.status})`
    : "Not started (use harness:advance to create backlog)"

  return {
    doneTasks,
    totalTasks,
    percent,
    currentTask,
    currentMilestone,
    backlog,
    blockedTable,
    worktreeLines,
    currentTaskLabel,
    activityLog,
  }
}

function generateProgressIndexMarkdown(state: ProjectState): string {
  const snapshot = buildProgressSnapshot(state)

  return `# PROGRESS.md — ${state.projectInfo.displayName || state.projectInfo.name || "Project"}

> **For the next session's Agent**: Read this index first, then read \`docs/progress/\`, AGENTS.md and LEARNING.md, then pick up from the Current Task.

---

## Current Summary

**Current Phase**: ${state.phase}
**Current Milestone**: ${snapshot.currentMilestone ? `${snapshot.currentMilestone.id} — ${snapshot.currentMilestone.name}` : "Not yet created"}
**Current Worktree**: \`${nextWorktreePath(state, snapshot.currentMilestone)}\`
**Current Task**: ${snapshot.currentTaskLabel}
**Overall Progress**: [${progressBar(snapshot.doneTasks, snapshot.totalTasks)}] ${snapshot.doneTasks}/${snapshot.totalTasks} Tasks (${snapshot.percent}%)
**Last Updated**: ${state.updatedAt}

---

## Module Index

1. [01 Summary](./progress/01-summary.md)
2. [02 Current State](./progress/02-current-state.md)
3. [03 Backlog](./progress/03-backlog.md)
4. [04 Blockers](./progress/04-blockers.md)
5. [05 Worktrees](./progress/05-worktrees.md)
6. [06 Next Session](./progress/06-next-session.md)
7. [07 Activity](./progress/07-activity.md)
`
}

