export const SURFACE_LABELS: Record<ProjectType, string> = {
  "web-app": "Web App",
  "ios-app": "iOS App",
  "android-app": "Android App",
  api: "API",
  "mobile-cross-platform": "Cross-Platform Mobile",
  cli: "CLI",
  agent: "Agent Project",
