#!/usr/bin/env bun
/**
 * .harness/state.ts
 *
 * Controlled state mutation entrypoint for interactive phases, hand-offs, and tests.
 * Supports:
 * - viewing the current state
 * - updating phase
 * - deep-merging a JSON patch into .harness/state.json
 */

import { existsSync, readFileSync } from "fs"
import type { Phase, ProjectState } from "./types"
import { readState, updateState } from "./runtime/state-core"

type CliArgs = {
  patch?: string
  patchFile?: string
  phase?: Phase
  show: boolean
}

function parseArgs(argv: string[]): CliArgs {
  const args: CliArgs = { show: false }

  for (let index = 0; index < argv.length; index++) {
    const current = argv[index]
    if (!current?.startsWith("--")) continue

    const [rawKey, inlineValue] = current.slice(2).split("=", 2)
    const nextValue = inlineValue ?? argv[index + 1]
    const consumesNext = inlineValue === undefined && nextValue && !nextValue.startsWith("--")

    switch (rawKey) {
      case "patch":
        args.patch = inlineValue ?? (consumesNext ? nextValue : undefined)
        break
      case "patchFile":
        args.patchFile = inlineValue ?? (consumesNext ? nextValue : undefined)
        break
      case "phase":
        args.phase = (inlineValue ?? (consumesNext ? nextValue : undefined)) as Phase | undefined
        break
      case "show":
        args.show = true
        break
      default:
        throw new Error(`Unknown flag --${rawKey}`)
    }

    if (consumesNext) index++
  }

  return args
}

function readPatch(args: CliArgs): Partial<ProjectState> {
  if (args.patch && args.patchFile) {
    throw new Error("Use either --patch or --patchFile, not both.")
  }

  if (args.patchFile) {
    if (!existsSync(args.patchFile)) {
      throw new Error(`Patch file not found: ${args.patchFile}`)
    }
    return JSON.parse(readFileSync(args.patchFile, "utf-8")) as Partial<ProjectState>
  }

  if (args.patch) {
    return JSON.parse(args.patch) as Partial<ProjectState>
  }

  return {}
}

function mergePhase(
  patch: Partial<ProjectState>,
  phase: Phase | undefined,
): Partial<ProjectState> {
  if (!phase) return patch
  return { ...patch, phase }
}

const args = parseArgs(process.argv.slice(2))

if (args.show) {
  console.log(JSON.stringify(readState(), null, 2))
  process.exit(0)
}

const patch = mergePhase(readPatch(args), args.phase)
if (Object.keys(patch).length === 0) {
  console.error("Usage: bun .harness/state.ts --show | --phase=EXECUTING | --patch='{\"phase\":\"TECH_STACK\"}'")
  process.exit(1)
}

const next = updateState(patch)
console.log(`✅ state updated (${next.phase})`)

#!/usr/bin/env bun

import { getManagedDocSpecs, syncManagedFiles } from "./runtime/generated-files"
import { readState, writeState } from "./runtime/state-core"

const state = readState()
const results = syncManagedFiles(getManagedDocSpecs(state))
const updated = writeState(state)

const changed = results.filter(result => result.changed).length
console.log(`✅ sync-docs complete (${changed}/${results.length} file(s) changed)`)
console.log(`   Phase: ${updated.phase}`)

#!/usr/bin/env bun

import { existsSync, mkdirSync, writeFileSync } from "fs"
import { getManagedSkillSpecs, syncManagedFiles } from "./runtime/generated-files"
import { syncLocalBootstrapManifest } from "./runtime/local-bootstrap"
import { readState, writeState } from "./runtime/state-core"
import { hasAgentSurface } from "./runtime/surfaces"

const state = readState()

if (!hasAgentSurface(state.projectInfo.types)) {
  console.log("ℹ️  No agent surface is enabled. sync-skills is a no-op.")
  process.exit(0)
}

mkdirSync("packages/shared/api", { recursive: true })
if (!existsSync("packages/shared/api/README.md")) {
  writeFileSync(
    "packages/shared/api/README.md",
    "# Shared API wrappers\n\nAdd agent-facing service wrappers under this directory.\n",
  )
}

const results = syncManagedFiles(getManagedSkillSpecs(state))
writeState(state)
syncLocalBootstrapManifest()

const changed = results.filter(result => result.changed).length
console.log(`✅ sync-skills complete (${changed}/${results.length} file(s) changed)`)

#!/usr/bin/env bun
/**
 * .harness/validate.ts
 *
 * Harness validation script — cross-platform (Windows + macOS + Linux)
 * Corresponds to spec: references/gates-and-guardians.md
 */

import type { Phase } from "./types"
import { validateEnv, validateGuardians } from "./runtime/validation/env-and-guardians"
import { validateMilestone, fullValidation } from "./runtime/validation/milestone-score"
import { validatePhaseGate } from "./runtime/validation/phase"
import { createReporter } from "./runtime/validation/reporter"
import { loadState, saveState, syncStateFromFilesystem } from "./runtime/validation/state"
import { validateTask } from "./runtime/validation/task"

const args = process.argv.slice(2)
const reporter = createReporter()

if (args.includes("--env")) {
  await validateEnv(reporter)
  reporter.finish()
}

if (args.includes("--guardian")) {
  await validateGuardians(reporter)
  reporter.finish()
}

const loadedState = loadState(true)
const state = syncStateFromFilesystem(loadedState!)
saveState(state)

if (args.includes("--phase")) {
  const phase = args[args.indexOf("--phase") + 1] as Phase | undefined
  if (!phase) {
    reporter.failSoft("Please provide a --phase value, e.g. bun .harness/validate.ts --phase EXECUTING")
    reporter.finish()
  }
  await validatePhaseGate(phase!, state, reporter)
  reporter.finish()
}

if (args.includes("--task")) {
  const taskId = args[args.indexOf("--task") + 1]
  if (!taskId) {
    reporter.failSoft("Please provide a --task value, e.g. bun .harness/validate.ts --task T001")
    reporter.finish()
  }
  await validateTask(taskId!, state, reporter)
  reporter.finish()
}

if (args.includes("--milestone")) {
  const milestoneId = args[args.indexOf("--milestone") + 1]
  if (!milestoneId) {
    reporter.failSoft("Please provide a --milestone value, e.g. bun .harness/validate.ts --milestone M1")
    reporter.finish()
  }
  await validateMilestone(milestoneId!, state, reporter)
  reporter.finish()
}

fullValidation(state, reporter)
reporter.finish()
